export interface CoordinatorProfile {
  nombre: string;
  email: string;
}

export interface PatientData {
  id: string;
  nombre: string;
  edad: string;
  sexo: string;
  observaciones: string;
  telefono: string;
  email: string;
  status: 'pending' | 'completed' | 'waiting';
  answers?: Record<string, string>;
  conversationSummary?: string;
}

export interface Question {
  id: string;
  scenario: string;
  options: {
    key: string;
    text: string;
  }[];
  speechScript?: string;
  audioFileUrl?: string; // Nuevo campo para MP3 personalizado
  isScale?: boolean;
  scaleLabel?: string;
  followUp?: string;
}

export enum Voice {
  MALE = 'Puck', // Restaurada a Puck (Voz masculina natural y estable)
  FEMALE = 'Kore', // Cambiada a Kore (Voz femenina calmada y terapéutica)
  NONE = 'none'
}

export type View = 'COORDINATOR' | 'PATIENT_SESSION' | 'LANDING';

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData, isEditorMode, onExitEditor }) => {
  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Refs para el motor de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null); 

  // Cache de inicio (Intro + Nombre)
  const startupCache = useRef<Record<string, AudioBuffer>>({});
  const hasPrefetchedStartup = useRef(false);

  // Control de errores global
  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  useEffect(() => {
    if (step === 'verification' || step === 'finish') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step, currentQuestionIndex]);

  // Precarga de Audio al Inicio
  useEffect(() => {
    const prefetchStartupAudio = async () => {
      // Si no hay voz, no intentamos precargar
      if (voice === Voice.NONE || hasPrefetchedStartup.current || step !== 'intro') return;

      initAudio();
      const signal = new AbortController().signal; // Dummy signal
      hasPrefetchedStartup.current = true;

      const introKey = 'intro';
      const nameKey = 'nameQ';
      const nameQuestionText = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

      // 1. Cargar Intro
      if (introConfig.audioUrl) {
         try {
           const res = await fetch(introConfig.audioUrl);
           const ab = await res.arrayBuffer();
           if (audioContextRef.current) startupCache.current[introKey] = await audioContextRef.current.decodeAudioData(ab);
         } catch(e) {}
      } else {
         const buffer = await generateAudioBuffer(introConfig.text, signal);
         if (buffer) startupCache.current[introKey] = buffer;
      }

      // 2. Cargar Pregunta Nombre (Simultáneo en background)
      const bufferName = await generateAudioBuffer(nameQuestionText, signal);
      if (bufferName) startupCache.current[nameKey] = bufferName;
    };

    const t = setTimeout(prefetchStartupAudio, 500);
    return () => clearTimeout(t);
  }, [voice, step, introConfig]); 

  useEffect(() => {
    hasPrefetchedStartup.current = false;
    startupCache.current = {};
  }, [voice]);


  // --- MOTOR DE AUDIO ---

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const generateAudioBuffer = async (text: string, signal: AbortSignal): Promise<AudioBuffer | null> => {
    try {
      const base64Audio = await gemini.generateSpeechBlock(text, voice);
      if (signal.aborted) return null;

      if (!base64Audio) {
         // Si falla, retornamos null para usar fallback nativo SOLO esta vez
         return null; 
      }

      if (audioContextRef.current) {
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current, 24000, 1);
      }
    } catch (e) {
      // Fallback temporal si hay error
      return null;
    }
    return null;
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES'; // Prioridad Español de España

      const voices = window.speechSynthesis.getVoices();
      const esVoices = voices.filter(v => v.lang.startsWith('es'));
      const spainVoices = esVoices.filter(v => v.lang === 'es-ES' || v.lang === 'es_ES');

      let selectedVoice = null;

      // Intentar buscar voces de mejor calidad si están disponibles
      if (voice === Voice.FEMALE) {
        selectedVoice = spainVoices.find(v => v.name.includes('Google') || v.name.includes('Monica'));
      } else {
        selectedVoice = spainVoices.find(v => v.name.includes('Google') || v.name.includes('Pablo') || v.name.includes('Jorge'));
      }

      // Fallbacks
      if (!selectedVoice) selectedVoice = spainVoices[0];
      if (!selectedVoice) selectedVoice = esVoices[0];

      utterance.voice = selectedVoice || null;

      // ELIMINADAS las manipulaciones de pitch y rate que causaban el efecto robótico
      utterance.pitch = 1.0; 
      utterance.rate = 1.0; 

      utterance.onend = () => { resolve(); };
      utterance.onerror = () => { resolve(); };

      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  // Función principal de secuenciación
  const runSequence = async (segments: { text: string, type: 'text' | 'option', key?: string, audioUrl?: string, cacheKey?: string }[], cacheOverride?: Record<string, AudioBuffer>) => {
    if (voice === Voice.NONE) {
      segments.forEach(seg => {
        if (seg.type === 'option' && seg.key) setVisibleOptions(prev => [...prev, seg.key!]);
      });
      return;
    }

    initAudio();
    stopAudio(); 

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    // 1. PREPARAR PROMESAS (O recuperar de caché)
    const promises = segments.map(async (seg) => {
      // A. Revisar Cache de Inicio
      if (seg.cacheKey && cacheOverride && cacheOverride[seg.cacheKey]) {
        return cacheOverride[seg.cacheKey];
      }

      // B. Fetch Normal
      if (seg.audioUrl) {
        try {
          const res = await fetch(seg.audioUrl);
          const ab = await res.arrayBuffer();
          if (audioContextRef.current) {
             return await audioContextRef.current.decodeAudioData(ab);
          }
        } catch (e) { return null; }
      } else {
        return generateAudioBuffer(seg.text, signal);
      }
      return null;
    });

    // 2. REPRODUCIR EN SERIE
    for (let i = 0; i < segments.length; i++) {
      if (signal.aborted) break;

      const segment = segments[i];
      let buffer = null;

      buffer = await promises[i];

      if (segment.type === 'option' && segment.key) {
        setVisibleOptions(prev => [...prev, segment.key!]);
      }

      if (buffer && !signal.aborted) {
        await playBuffer(buffer);
      } else if (!signal.aborted) {
        // Fallback Nativo (solo si buffer es null)
        await nativeSpeak(segment.text);
      }
    }

    setIsSpeaking(false);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  const startSession = async () => {
    initAudio();
    setStep('verification');

    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');
    setTimeout(() => addMessage(nameQuestion, 'ia'), 500);

    await runSequence([
      { text: introText, type: 'text', audioUrl: introConfig.audioUrl, cacheKey: 'intro' },
      { text: nameQuestion, type: 'text', cacheKey: 'nameQ' }
    ], startupCache.current);
  };

  const handleVerification = async (nameInput: string) => {
    const nameToMatch = isEditorMode ? "Coordinador" : (patientData.nombre || "");
    const inputClean = nameInput.trim().toLowerCase();
    const expectedClean = nameToMatch.split(' ')[0].toLowerCase();

    addMessage(nameInput, 'user');

    if (inputClean.includes(expectedClean) || expectedClean.includes(inputClean) || isEditorMode) {
      stopAudio();
      const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
      addMessage(welcome, 'ia');
      await runSequence([{ text: welcome, type: 'text' }]);

      setTimeout(() => {
        setStep('questionnaire');
        loadQuestion(0);
      }, 500); 
    } else {
      const errorMsg = "Parece que se ha cometido un error, este cuestionario está dirigido a otra persona. Repítame el nombre otra vez.";
      addMessage(errorMsg, 'ia');
      runSequence([{ text: errorMsg, type: 'text' }]);
    }
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${patientData.nombre || 'amigo/a'}, en breve nos volveremos a poner en contacto.`;
      addMessage(goodbye, 'ia');
      runSequence([{ text: goodbye, type: 'text' }]);
      return;
    }

    const segments: any[] = [];
    const scenarioText = q.speechScript || q.scenario;
    segments.push({ text: scenarioText, type: 'text', audioUrl: q.audioFileUrl });

    if (!q.audioFileUrl && !q.speechScript) {
      q.options.forEach(opt => {
        segments.push({ 
          text: `Opción ${opt.key.toUpperCase()}... ${opt.text}`, 
          type: 'option', 
          key: opt.key 
        });
      });
      if (index === 0) {
        segments.push({ text: "¿Con cuál de estas situaciones te sientes más identificado?", type: 'text' });
      }
    } else {
        q.options.forEach(opt => {
             setVisibleOptions(prev => [...prev, opt.key]);
        });
    }

    runSequence(segments);
  };

  const handleAnswer = async (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-16 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <h2 className={`text-3xl font-bold mb-4 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>Proceso Finalizado</h2>
              <p className={`font-black max-w-xs mx-auto text-lg uppercase tracking-tight ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Tus respuestas nos ayudarán a trazar el camino.</p>
              {isEditorMode && <Button onClick={onExitEditor} className="mt-10">Cerrar Editor</Button>}

              <div className="mt-12 space-y-4 px-6 text-left">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
              </div>
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl,
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Tu nombre..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

export interface CoordinatorProfile {
  nombre: string;
  email: string;
}

export interface PatientData {
  id: string;
  nombre: string;
  edad: string;
  sexo: string;
  observaciones: string;
  telefono: string;
  email: string;
  status: 'pending' | 'completed' | 'waiting';
  answers?: Record<string, string>;
  conversationSummary?: string;
}

export interface Question {
  id: string;
  scenario: string;
  options: {
    key: string;
    text: string;
  }[];
  speechScript?: string;
  audioFileUrl?: string; // Nuevo campo para MP3 personalizado
  isScale?: boolean;
  scaleLabel?: string;
  followUp?: string;
}

export enum Voice {
  MALE = 'Kore', // Asignada KORE a Masculino por petición (tono grave y calmado)
  FEMALE = 'Aoede', // Asignada AOEDE a Femenino (tono claramente femenino y profesional)
  NONE = 'none'
}

export type View = 'COORDINATOR' | 'PATIENT_SESSION' | 'LANDING';

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData, isEditorMode, onExitEditor }) => {
  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Refs para el motor de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null); 

  // Control de errores global
  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  useEffect(() => {
    if (step === 'verification' || step === 'finish') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step, currentQuestionIndex]);

  // --- MOTOR DE AUDIO ---

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const generateAudioBuffer = async (text: string, signal: AbortSignal): Promise<AudioBuffer | null> => {
    try {
      // Intento silenciado de obtener audio de la IA
      const base64Audio = await gemini.generateSpeechBlock(text, voice);
      if (signal.aborted) return null;

      if (!base64Audio) {
         return null; 
      }

      if (audioContextRef.current) {
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current, 24000, 1);
      }
    } catch (e) {
      return null;
    }
    return null;
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES';

      const voices = window.speechSynthesis.getVoices();

      // Lógica estricta de selección de voz nativa
      let selectedVoice = null;

      if (voice === Voice.FEMALE) {
        // Priorizar voces con nombres femeninos comunes en TTS
        selectedVoice = voices.find(v => 
          (v.lang.includes('es') && (
            v.name.includes('Monica') || 
            v.name.includes('Paulina') || 
            v.name.includes('Samantha') || 
            v.name.includes('Marta') ||
            // Google Español suele ser aguda/femenina por defecto
            v.name === 'Google español'
          ))
        );
      } else {
        // Priorizar voces masculinas
        selectedVoice = voices.find(v => 
          (v.lang.includes('es') && (
            v.name.includes('Jorge') || 
            v.name.includes('Juan') || 
            v.name.includes('Pablo') ||
            v.name.includes('Diego')
          ))
        );
      }

      // Fallback genérico si no encuentra las específicas
      if (!selectedVoice) {
         const esVoices = voices.filter(v => v.lang.startsWith('es'));
         selectedVoice = esVoices[0];
      }

      utterance.voice = selectedVoice || null;
      utterance.pitch = 1.0; 
      utterance.rate = 1.05; // Ligeramente más fluido

      utterance.onend = () => { resolve(); };
      utterance.onerror = () => { resolve(); };

      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  // Función principal de secuenciación
  const runSequence = async (segments: { text: string, type: 'text' | 'option', key?: string, audioUrl?: string, cacheKey?: string }[]) => {
    if (voice === Voice.NONE) {
      segments.forEach(seg => {
        if (seg.type === 'option' && seg.key) setVisibleOptions(prev => [...prev, seg.key!]);
      });
      return;
    }

    initAudio();
    stopAudio(); 

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    // Ejecución secuencial estricta para evitar bloqueos
    for (let i = 0; i < segments.length; i++) {
      if (signal.aborted) break;

      const segment = segments[i];
      let buffer = null;

      // Intentar obtener audio (IA o archivo)
      if (segment.audioUrl) {
        try {
          const res = await fetch(segment.audioUrl);
          const ab = await res.arrayBuffer();
          if (audioContextRef.current) {
             buffer = await audioContextRef.current.decodeAudioData(ab);
          }
        } catch (e) { buffer = null; }
      } else {
        buffer = await generateAudioBuffer(segment.text, signal);
      }

      if (segment.type === 'option' && segment.key) {
        setVisibleOptions(prev => [...prev, segment.key!]);
      }

      if (buffer && !signal.aborted) {
        await playBuffer(buffer);
      } else if (!signal.aborted) {
        // Si falla la IA o no hay buffer, usar nativo inmediatamente
        await nativeSpeak(segment.text);
      }
    }

    setIsSpeaking(false);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  const startSession = async () => {
    initAudio();
    setStep('verification');

    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');
    setTimeout(() => addMessage(nameQuestion, 'ia'), 500);

    await runSequence([
      { text: introText, type: 'text', audioUrl: introConfig.audioUrl },
      { text: nameQuestion, type: 'text' }
    ]);
  };

  const handleVerification = async (nameInput: string) => {
    const nameToMatch = isEditorMode ? "Coordinador" : (patientData.nombre || "");
    const inputClean = nameInput.trim().toLowerCase();
    const expectedClean = nameToMatch.split(' ')[0].toLowerCase();

    addMessage(nameInput, 'user');

    if (inputClean.includes(expectedClean) || expectedClean.includes(inputClean) || isEditorMode) {
      stopAudio();
      const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
      addMessage(welcome, 'ia');
      await runSequence([{ text: welcome, type: 'text' }]);

      setTimeout(() => {
        setStep('questionnaire');
        loadQuestion(0);
      }, 500); 
    } else {
      const errorMsg = "Parece que se ha cometido un error, este cuestionario está dirigido a otra persona. Repítame el nombre otra vez.";
      addMessage(errorMsg, 'ia');
      runSequence([{ text: errorMsg, type: 'text' }]);
    }
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${patientData.nombre || 'amigo/a'}, en breve nos volveremos a poner en contacto.`;
      addMessage(goodbye, 'ia');
      runSequence([{ text: goodbye, type: 'text' }]);
      return;
    }

    const segments: any[] = [];
    const scenarioText = q.speechScript || q.scenario;
    segments.push({ text: scenarioText, type: 'text', audioUrl: q.audioFileUrl });

    if (!q.audioFileUrl && !q.speechScript) {
      q.options.forEach(opt => {
        segments.push({ 
          text: `Opción ${opt.key.toUpperCase()}... ${opt.text}`, 
          type: 'option', 
          key: opt.key 
        });
      });
      if (index === 0) {
        segments.push({ text: "¿Con cuál de estas situaciones te sientes más identificado?", type: 'text' });
      }
    } else {
        q.options.forEach(opt => {
             setVisibleOptions(prev => [...prev, opt.key]);
        });
    }

    runSequence(segments);
  };

  const handleAnswer = async (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-16 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <h2 className={`text-3xl font-bold mb-4 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>Proceso Finalizado</h2>
              <p className={`font-black max-w-xs mx-auto text-lg uppercase tracking-tight ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Tus respuestas nos ayudarán a trazar el camino.</p>
              {isEditorMode && <Button onClick={onExitEditor} className="mt-10">Cerrar Editor</Button>}

              <div className="mt-12 space-y-4 px-6 text-left">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
              </div>
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl,
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Tu nombre..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

export interface CoordinatorProfile {
  nombre: string;
  email: string;
}

export interface PatientData {
  id: string;
  nombre: string;
  edad: string;
  sexo: string;
  observaciones: string;
  telefono: string;
  email: string;
  status: 'pending' | 'completed' | 'waiting';
  answers?: Record<string, string>;
  conversationSummary?: string;
}

export interface Question {
  id: string;
  scenario: string;
  options: {
    key: string;
    text: string;
  }[];
  speechScript?: string;
  audioFileUrl?: string; // Nuevo campo para MP3 personalizado
  isScale?: boolean;
  scaleLabel?: string;
  followUp?: string;
}

export enum Voice {
  MALE = 'Kore',   // Voz grave y calmada (la que te gustaba en el botón mujer)
  FEMALE = 'Aoede', // Voz aguda y profesional (misma tecnología Gemini)
  NONE = 'none'
}

export type View = 'COORDINATOR' | 'PATIENT_SESSION' | 'LANDING';

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData, isEditorMode, onExitEditor }) => {
  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Refs para el motor de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // INTERRUPTOR DE SEGURIDAD: Si falla la API una vez, se desactiva para toda la sesión.
  const apiDisabled = useRef(false);

  // Control de errores global
  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  useEffect(() => {
    if (step === 'verification' || step === 'finish') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step, currentQuestionIndex]);

  // --- MOTOR DE AUDIO ---

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const generateAudioBuffer = async (text: string, signal: AbortSignal): Promise<AudioBuffer | null> => {
    // Si ya falló antes, ni lo intentamos. Pasamos directo a fallback.
    if (apiDisabled.current) return null;

    try {
      const base64Audio = await gemini.generateSpeechBlock(text, voice);

      if (signal.aborted) return null;

      if (!base64Audio) {
         // Si la API devuelve vacío (error silencioso), activamos el interruptor
         apiDisabled.current = true;
         console.warn("API de voz falló, desactivando para el resto de la sesión.");
         return null; 
      }

      if (audioContextRef.current) {
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current, 24000, 1);
      }
    } catch (e) {
      apiDisabled.current = true;
      return null;
    }
    return null;
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES';

      const voices = window.speechSynthesis.getVoices();

      let selectedVoice = null;

      // Lógica de selección de voz nativa mejorada
      if (voice === Voice.FEMALE) {
        // Buscar voces femeninas específicas
        selectedVoice = voices.find(v => 
          v.lang.includes('es') && (
            v.name.includes('Monica') || 
            v.name.includes('Paulina') || 
            v.name.includes('Samantha') || 
            v.name.includes('Marta') ||
            v.name.includes('Amelia')
          )
        );
        // Fallback genérico femenino: Google Español suele ser femenino/agudo
        if (!selectedVoice) selectedVoice = voices.find(v => v.name === 'Google español');
      } else {
        // Buscar voces masculinas específicas
        selectedVoice = voices.find(v => 
          v.lang.includes('es') && (
            v.name.includes('Jorge') || 
            v.name.includes('Juan') || 
            v.name.includes('Pablo') ||
            v.name.includes('Diego')
          )
        );
      }

      // Último recurso
      if (!selectedVoice) {
         const esVoices = voices.filter(v => v.lang.startsWith('es'));
         selectedVoice = esVoices[0];
      }

      utterance.voice = selectedVoice || null;
      utterance.pitch = 1.0; 
      utterance.rate = 1.05; 

      utterance.onend = () => { resolve(); };
      utterance.onerror = () => { resolve(); };

      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  const runSequence = async (segments: { text: string, type: 'text' | 'option', key?: string, audioUrl?: string }[]) => {
    if (voice === Voice.NONE) {
      segments.forEach(seg => {
        if (seg.type === 'option' && seg.key) setVisibleOptions(prev => [...prev, seg.key!]);
      });
      return;
    }

    initAudio();
    stopAudio(); 

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    for (let i = 0; i < segments.length; i++) {
      if (signal.aborted) break;

      const segment = segments[i];
      let buffer = null;

      if (segment.audioUrl) {
        try {
          const res = await fetch(segment.audioUrl);
          const ab = await res.arrayBuffer();
          if (audioContextRef.current) {
             buffer = await audioContextRef.current.decodeAudioData(ab);
          }
        } catch (e) { buffer = null; }
      } else {
        // Aquí se decide si usar IA o fallback (si apiDisabled es true, devuelve null rápido)
        buffer = await generateAudioBuffer(segment.text, signal);
      }

      if (segment.type === 'option' && segment.key) {
        setVisibleOptions(prev => [...prev, segment.key!]);
      }

      if (buffer && !signal.aborted) {
        await playBuffer(buffer);
      } else if (!signal.aborted) {
        await nativeSpeak(segment.text);
      }
    }

    setIsSpeaking(false);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  const startSession = async () => {
    initAudio();
    setStep('verification');

    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');
    setTimeout(() => addMessage(nameQuestion, 'ia'), 500);

    await runSequence([
      { text: introText, type: 'text', audioUrl: introConfig.audioUrl },
      { text: nameQuestion, type: 'text' }
    ]);
  };

  const handleVerification = async (nameInput: string) => {
    const nameToMatch = isEditorMode ? "Coordinador" : (patientData.nombre || "");
    const inputClean = nameInput.trim().toLowerCase();
    const expectedClean = nameToMatch.split(' ')[0].toLowerCase();

    addMessage(nameInput, 'user');

    if (inputClean.includes(expectedClean) || expectedClean.includes(inputClean) || isEditorMode) {
      stopAudio();
      const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
      addMessage(welcome, 'ia');
      await runSequence([{ text: welcome, type: 'text' }]);

      setTimeout(() => {
        setStep('questionnaire');
        loadQuestion(0);
      }, 500); 
    } else {
      const errorMsg = "Parece que se ha cometido un error, este cuestionario está dirigido a otra persona. Repítame el nombre otra vez.";
      addMessage(errorMsg, 'ia');
      runSequence([{ text: errorMsg, type: 'text' }]);
    }
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${patientData.nombre || 'amigo/a'}, en breve nos volveremos a poner en contacto.`;
      addMessage(goodbye, 'ia');
      runSequence([{ text: goodbye, type: 'text' }]);
      return;
    }

    const segments: any[] = [];
    const scenarioText = q.speechScript || q.scenario;
    segments.push({ text: scenarioText, type: 'text', audioUrl: q.audioFileUrl });

    if (!q.audioFileUrl && !q.speechScript) {
      q.options.forEach(opt => {
        segments.push({ 
          text: `Opción ${opt.key.toUpperCase()}... ${opt.text}`, 
          type: 'option', 
          key: opt.key 
        });
      });
      if (index === 0) {
        segments.push({ text: "¿Con cuál de estas situaciones te sientes más identificado?", type: 'text' });
      }
    } else {
        q.options.forEach(opt => {
             setVisibleOptions(prev => [...prev, opt.key]);
        });
    }

    runSequence(segments);
  };

  const handleAnswer = async (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-16 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <h2 className={`text-3xl font-bold mb-4 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>Proceso Finalizado</h2>
              <p className={`font-black max-w-xs mx-auto text-lg uppercase tracking-tight ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Tus respuestas nos ayudarán a trazar el camino.</p>
              {isEditorMode && <Button onClick={onExitEditor} className="mt-10">Cerrar Editor</Button>}

              <div className="mt-12 space-y-4 px-6 text-left">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
              </div>
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl,
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Tu nombre..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData, isEditorMode, onExitEditor }) => {
  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Refs para el motor de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // INTERRUPTOR DE SEGURIDAD: Si falla la API una vez, se desactiva para toda la sesión.
  const apiDisabled = useRef(false);

  // Control de errores global
  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  useEffect(() => {
    if (step === 'verification' || step === 'finish') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step, currentQuestionIndex]);

  // --- MOTOR DE AUDIO ---

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const generateAudioBuffer = async (text: string, signal: AbortSignal): Promise<AudioBuffer | null> => {
    // Si ya falló antes, ni lo intentamos. Pasamos directo a fallback.
    if (apiDisabled.current) return null;

    try {
      const base64Audio = await gemini.generateSpeechBlock(text, voice);

      if (signal.aborted) return null;

      if (!base64Audio) {
         // Si la API devuelve vacío (error silencioso), activamos el interruptor
         apiDisabled.current = true;
         console.warn("API de voz falló, desactivando para el resto de la sesión.");
         return null; 
      }

      if (audioContextRef.current) {
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current, 24000, 1);
      }
    } catch (e) {
      apiDisabled.current = true;
      return null;
    }
    return null;
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES';

      const voices = window.speechSynthesis.getVoices();

      let selectedVoice = null;

      // Lógica de selección de voz nativa INTERCAMBIADA por solicitud
      if (voice === Voice.FEMALE) {
        // Solicitud: En modo Femenino, usar voces del navegador Masculinas
        selectedVoice = voices.find(v => 
          v.lang.includes('es') && (
            v.name.includes('Jorge') || 
            v.name.includes('Juan') || 
            v.name.includes('Pablo') ||
            v.name.includes('Diego')
          )
        );
      } else {
        // Solicitud: En modo Masculino, usar voces del navegador Femeninas
        selectedVoice = voices.find(v => 
          v.lang.includes('es') && (
            v.name.includes('Monica') || 
            v.name.includes('Paulina') || 
            v.name.includes('Samantha') || 
            v.name.includes('Marta') ||
            v.name.includes('Amelia')
          )
        );
        // Fallback genérico femenino
        if (!selectedVoice) selectedVoice = voices.find(v => v.name === 'Google español');
      }

      // Último recurso
      if (!selectedVoice) {
         const esVoices = voices.filter(v => v.lang.startsWith('es'));
         selectedVoice = esVoices[0];
      }

      utterance.voice = selectedVoice || null;
      utterance.pitch = 1.0; 
      utterance.rate = 1.05; 

      utterance.onend = () => { resolve(); };
      utterance.onerror = () => { resolve(); };

      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  const runSequence = async (segments: { text: string, type: 'text' | 'option', key?: string, audioUrl?: string }[]) => {
    if (voice === Voice.NONE) {
      segments.forEach(seg => {
        if (seg.type === 'option' && seg.key) setVisibleOptions(prev => [...prev, seg.key!]);
      });
      return;
    }

    initAudio();
    stopAudio(); 

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    for (let i = 0; i < segments.length; i++) {
      if (signal.aborted) break;

      const segment = segments[i];
      let buffer = null;

      if (segment.audioUrl) {
        try {
          const res = await fetch(segment.audioUrl);
          const ab = await res.arrayBuffer();
          if (audioContextRef.current) {
             buffer = await audioContextRef.current.decodeAudioData(ab);
          }
        } catch (e) { buffer = null; }
      } else {
        // Aquí se decide si usar IA o fallback (si apiDisabled es true, devuelve null rápido)
        buffer = await generateAudioBuffer(segment.text, signal);
      }

      if (segment.type === 'option' && segment.key) {
        setVisibleOptions(prev => [...prev, segment.key!]);
      }

      if (buffer && !signal.aborted) {
        await playBuffer(buffer);
      } else if (!signal.aborted) {
        await nativeSpeak(segment.text);
      }
    }

    setIsSpeaking(false);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  const startSession = async () => {
    initAudio();
    setStep('verification');

    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');
    setTimeout(() => addMessage(nameQuestion, 'ia'), 500);

    await runSequence([
      { text: introText, type: 'text', audioUrl: introConfig.audioUrl },
      { text: nameQuestion, type: 'text' }
    ]);
  };

  const handleVerification = async (nameInput: string) => {
    const nameToMatch = isEditorMode ? "Coordinador" : (patientData.nombre || "");
    const inputClean = nameInput.trim().toLowerCase();
    const expectedClean = nameToMatch.split(' ')[0].toLowerCase();

    addMessage(nameInput, 'user');

    if (inputClean.includes(expectedClean) || expectedClean.includes(inputClean) || isEditorMode) {
      stopAudio();
      const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
      addMessage(welcome, 'ia');
      await runSequence([{ text: welcome, type: 'text' }]);

      setTimeout(() => {
        setStep('questionnaire');
        loadQuestion(0);
      }, 500); 
    } else {
      const errorMsg = "Parece que se ha cometido un error, este cuestionario está dirigido a otra persona. Repítame el nombre otra vez.";
      addMessage(errorMsg, 'ia');
      runSequence([{ text: errorMsg, type: 'text' }]);
    }
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${patientData.nombre || 'amigo/a'}, en breve nos volveremos a poner en contacto.`;
      addMessage(goodbye, 'ia');
      runSequence([{ text: goodbye, type: 'text' }]);
      return;
    }

    const segments: any[] = [];
    const scenarioText = q.speechScript || q.scenario;
    segments.push({ text: scenarioText, type: 'text', audioUrl: q.audioFileUrl });

    if (!q.audioFileUrl && !q.speechScript) {
      q.options.forEach(opt => {
        segments.push({ 
          text: `Opción ${opt.key.toUpperCase()}... ${opt.text}`, 
          type: 'option', 
          key: opt.key 
        });
      });
      if (index === 0) {
        segments.push({ text: "¿Con cuál de estas situaciones te sientes más identificado?", type: 'text' });
      }
    } else {
        q.options.forEach(opt => {
             setVisibleOptions(prev => [...prev, opt.key]);
        });
    }

    runSequence(segments);
  };

  const handleAnswer = async (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-16 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <h2 className={`text-3xl font-bold mb-4 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>Proceso Finalizado</h2>
              <p className={`font-black max-w-xs mx-auto text-lg uppercase tracking-tight ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Tus respuestas nos ayudarán a trazar el camino.</p>
              {isEditorMode && <Button onClick={onExitEditor} className="mt-10">Cerrar Editor</Button>}

              <div className="mt-12 space-y-4 px-6 text-left">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
              </div>
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl, 
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Tu nombre..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData, isEditorMode, onExitEditor }) => {
  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Refs para el motor de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // INTERRUPTOR DE SEGURIDAD: Si falla la API una vez, se desactiva para toda la sesión.
  const apiDisabled = useRef(false);

  // Control de errores global
  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  useEffect(() => {
    if (step === 'verification' || step === 'finish') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step, currentQuestionIndex]);

  // --- MOTOR DE AUDIO ---

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const generateAudioBuffer = async (text: string, signal: AbortSignal): Promise<AudioBuffer | null> => {
    // Si ya falló antes, ni lo intentamos. Pasamos directo a fallback.
    if (apiDisabled.current) return null;

    try {
      const base64Audio = await gemini.generateSpeechBlock(text, voice);

      if (signal.aborted) return null;

      if (!base64Audio) {
         // Si la API devuelve vacío (error silencioso), activamos el interruptor
         apiDisabled.current = true;
         console.warn("API de voz falló, desactivando para el resto de la sesión.");
         return null; 
      }

      if (audioContextRef.current) {
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current, 24000, 1);
      }
    } catch (e) {
      apiDisabled.current = true;
      return null;
    }
    return null;
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES';

      const voices = window.speechSynthesis.getVoices();

      let selectedVoice = null;

      if (voice === Voice.FEMALE) {
        // CORRECCIÓN: Prioridad absoluta a 'Google español' y voces femeninas de alta calidad
        // Esto elimina el sonido robótico o masculino.
        selectedVoice = voices.find(v => 
          v.name === 'Google español' || 
          v.name === 'Google Español' ||
          (v.lang.includes('es') && (
            v.name.includes('Microsoft Elena') ||
            v.name.includes('Paulina') || 
            v.name.includes('Monica') || 
            v.name.includes('Samantha') || 
            v.name.includes('Marta')
          ))
        );
      } else {
        // Voz Masculina: Busca voces masculinas estándar (Jorge/Pablo/etc)
        selectedVoice = voices.find(v => 
          v.lang.includes('es') && (
            v.name.includes('Jorge') || 
            v.name.includes('Juan') || 
            v.name.includes('Pablo') ||
            v.name.includes('Diego') ||
            v.name.includes('Alvaro')
          )
        );
      }

      // Último recurso: cualquier voz en español
      if (!selectedVoice) {
         const esVoices = voices.filter(v => v.lang.startsWith('es'));
         selectedVoice = esVoices[0];
      }

      utterance.voice = selectedVoice || null;
      utterance.pitch = 1.0; 
      utterance.rate = 1.05; 

      utterance.onend = () => { resolve(); };
      utterance.onerror = () => { resolve(); };

      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  const runSequence = async (segments: { text: string, type: 'text' | 'option', key?: string, audioUrl?: string }[]) => {
    if (voice === Voice.NONE) {
      segments.forEach(seg => {
        if (seg.type === 'option' && seg.key) setVisibleOptions(prev => [...prev, seg.key!]);
      });
      return;
    }

    initAudio();
    stopAudio(); 

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    for (let i = 0; i < segments.length; i++) {
      if (signal.aborted) break;

      const segment = segments[i];
      let buffer = null;

      if (segment.audioUrl) {
        try {
          const res = await fetch(segment.audioUrl);
          const ab = await res.arrayBuffer();
          if (audioContextRef.current) {
             buffer = await audioContextRef.current.decodeAudioData(ab);
          }
        } catch (e) { buffer = null; }
      } else {
        // Aquí se decide si usar IA o fallback (si apiDisabled es true, devuelve null rápido)
        buffer = await generateAudioBuffer(segment.text, signal);
      }

      if (segment.type === 'option' && segment.key) {
        setVisibleOptions(prev => [...prev, segment.key!]);
      }

      if (buffer && !signal.aborted) {
        await playBuffer(buffer);
      } else if (!signal.aborted) {
        await nativeSpeak(segment.text);
      }
    }

    setIsSpeaking(false);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  const startSession = async () => {
    initAudio();
    setStep('verification');

    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');
    setTimeout(() => addMessage(nameQuestion, 'ia'), 500);

    await runSequence([
      { text: introText, type: 'text', audioUrl: introConfig.audioUrl },
      { text: nameQuestion, type: 'text' }
    ]);
  };

  const handleVerification = async (nameInput: string) => {
    const nameToMatch = isEditorMode ? "Coordinador" : (patientData.nombre || "");
    const inputClean = nameInput.trim().toLowerCase();
    const expectedClean = nameToMatch.split(' ')[0].toLowerCase();

    addMessage(nameInput, 'user');

    if (inputClean.includes(expectedClean) || expectedClean.includes(inputClean) || isEditorMode) {
      stopAudio();
      const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
      addMessage(welcome, 'ia');
      await runSequence([{ text: welcome, type: 'text' }]);

      setTimeout(() => {
        setStep('questionnaire');
        loadQuestion(0);
      }, 500); 
    } else {
      const errorMsg = "Parece que se ha cometido un error, este cuestionario está dirigido a otra persona. Repítame el nombre otra vez.";
      addMessage(errorMsg, 'ia');
      runSequence([{ text: errorMsg, type: 'text' }]);
    }
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${patientData.nombre || 'amigo/a'}, en breve nos volveremos a poner en contacto.`;
      addMessage(goodbye, 'ia');
      runSequence([{ text: goodbye, type: 'text' }]);
      return;
    }

    const segments: any[] = [];
    const scenarioText = q.speechScript || q.scenario;
    segments.push({ text: scenarioText, type: 'text', audioUrl: q.audioFileUrl });

    if (!q.audioFileUrl && !q.speechScript) {
      q.options.forEach(opt => {
        segments.push({ 
          text: `Opción ${opt.key.toUpperCase()}... ${opt.text}`, 
          type: 'option', 
          key: opt.key 
        });
      });
      if (index === 0) {
        segments.push({ text: "¿Con cuál de estas situaciones te sientes más identificado?", type: 'text' });
      }
    } else {
        q.options.forEach(opt => {
             setVisibleOptions(prev => [...prev, opt.key]);
        });
    }

    runSequence(segments);
  };

  const handleAnswer = async (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-16 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <h2 className={`text-3xl font-bold mb-4 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>Proceso Finalizado</h2>
              <p className={`font-black max-w-xs mx-auto text-lg uppercase tracking-tight ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Tus respuestas nos ayudarán a trazar el camino.</p>
              {isEditorMode && <Button onClick={onExitEditor} className="mt-10">Cerrar Editor</Button>}

              <div className="mt-12 space-y-4 px-6 text-left">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
              </div>
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl, 
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Tu nombre..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData, isEditorMode, onExitEditor }) => {
  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Refs para el motor de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // INTERRUPTOR DE SEGURIDAD: Si falla la API una vez, se desactiva para toda la sesión.
  const apiDisabled = useRef(false);

  // Control de errores global
  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  useEffect(() => {
    if (step === 'verification' || step === 'finish') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step, currentQuestionIndex]);

  // --- MOTOR DE AUDIO ---

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const generateAudioBuffer = async (text: string, signal: AbortSignal): Promise<AudioBuffer | null> => {
    // Si ya falló antes, ni lo intentamos. Pasamos directo a fallback.
    if (apiDisabled.current) return null;

    try {
      const base64Audio = await gemini.generateSpeechBlock(text, voice);

      if (signal.aborted) return null;

      if (!base64Audio) {
         // Si la API devuelve vacío (error silencioso), activamos el interruptor
         apiDisabled.current = true;
         console.warn("API de voz falló, desactivando para el resto de la sesión.");
         return null; 
      }

      if (audioContextRef.current) {
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current, 24000, 1);
      }
    } catch (e) {
      apiDisabled.current = true;
      return null;
    }
    return null;
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES';

      const voices = window.speechSynthesis.getVoices();

      let selectedVoice = null;

      if (voice === Voice.FEMALE) {
        // INTERCAMBIO: Botón MUJER -> Busca voces MASCULINAS (Jorge, Pablo)
        selectedVoice = voices.find(v => 
          v.lang.includes('es') && (
            v.name.includes('Jorge') || 
            v.name.includes('Juan') || 
            v.name.includes('Pablo') ||
            v.name.includes('Diego') ||
            v.name.includes('Alvaro')
          )
        );
      } else {
        // INTERCAMBIO: Botón HOMBRE -> Busca voces FEMENINAS (Google español, Elena)
        selectedVoice = voices.find(v => 
          v.name === 'Google español' || 
          v.name === 'Google Español' ||
          (v.lang.includes('es') && (
            v.name.includes('Microsoft Elena') ||
            v.name.includes('Paulina') || 
            v.name.includes('Monica') || 
            v.name.includes('Samantha') || 
            v.name.includes('Marta')
          ))
        );
      }

      // Último recurso: cualquier voz en español
      if (!selectedVoice) {
         const esVoices = voices.filter(v => v.lang.startsWith('es'));
         selectedVoice = esVoices[0];
      }

      utterance.voice = selectedVoice || null;
      utterance.pitch = 1.0; 
      utterance.rate = 1.05; 

      utterance.onend = () => { resolve(); };
      utterance.onerror = () => { resolve(); };

      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  const runSequence = async (segments: { text: string, type: 'text' | 'option', key?: string, audioUrl?: string }[]) => {
    if (voice === Voice.NONE) {
      segments.forEach(seg => {
        if (seg.type === 'option' && seg.key) setVisibleOptions(prev => [...prev, seg.key!]);
      });
      return;
    }

    initAudio();
    stopAudio(); 

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    for (let i = 0; i < segments.length; i++) {
      if (signal.aborted) break;

      const segment = segments[i];
      let buffer = null;

      if (segment.audioUrl) {
        try {
          const res = await fetch(segment.audioUrl);
          const ab = await res.arrayBuffer();
          if (audioContextRef.current) {
             buffer = await audioContextRef.current.decodeAudioData(ab);
          }
        } catch (e) { buffer = null; }
      } else {
        // Aquí se decide si usar IA o fallback (si apiDisabled es true, devuelve null rápido)
        buffer = await generateAudioBuffer(segment.text, signal);
      }

      if (segment.type === 'option' && segment.key) {
        setVisibleOptions(prev => [...prev, segment.key!]);
      }

      if (buffer && !signal.aborted) {
        await playBuffer(buffer);
      } else if (!signal.aborted) {
        await nativeSpeak(segment.text);
      }
    }

    setIsSpeaking(false);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  const startSession = async () => {
    initAudio();
    setStep('verification');

    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');
    setTimeout(() => addMessage(nameQuestion, 'ia'), 500);

    await runSequence([
      { text: introText, type: 'text', audioUrl: introConfig.audioUrl },
      { text: nameQuestion, type: 'text' }
    ]);
  };

  const handleVerification = async (nameInput: string) => {
    const nameToMatch = isEditorMode ? "Coordinador" : (patientData.nombre || "");
    const inputClean = nameInput.trim().toLowerCase();
    const expectedClean = nameToMatch.split(' ')[0].toLowerCase();

    addMessage(nameInput, 'user');

    if (inputClean.includes(expectedClean) || expectedClean.includes(inputClean) || isEditorMode) {
      stopAudio();
      const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
      addMessage(welcome, 'ia');
      await runSequence([{ text: welcome, type: 'text' }]);

      setTimeout(() => {
        setStep('questionnaire');
        loadQuestion(0);
      }, 500); 
    } else {
      const errorMsg = "Parece que se ha cometido un error, este cuestionario está dirigido a otra persona. Repítame el nombre otra vez.";
      addMessage(errorMsg, 'ia');
      runSequence([{ text: errorMsg, type: 'text' }]);
    }
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${patientData.nombre || 'amigo/a'}, en breve nos volveremos a poner en contacto.`;
      addMessage(goodbye, 'ia');
      runSequence([{ text: goodbye, type: 'text' }]);
      return;
    }

    const segments: any[] = [];
    const scenarioText = q.speechScript || q.scenario;
    segments.push({ text: scenarioText, type: 'text', audioUrl: q.audioFileUrl });

    if (!q.audioFileUrl && !q.speechScript) {
      q.options.forEach(opt => {
        segments.push({ 
          text: `Opción ${opt.key.toUpperCase()}... ${opt.text}`, 
          type: 'option', 
          key: opt.key 
        });
      });
      if (index === 0) {
        segments.push({ text: "¿Con cuál de estas situaciones te sientes más identificado?", type: 'text' });
      }
    } else {
        q.options.forEach(opt => {
             setVisibleOptions(prev => [...prev, opt.key]);
        });
    }

    runSequence(segments);
  };

  const handleAnswer = async (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-16 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <h2 className={`text-3xl font-bold mb-4 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>Proceso Finalizado</h2>
              <p className={`font-black max-w-xs mx-auto text-lg uppercase tracking-tight ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Tus respuestas nos ayudarán a trazar el camino.</p>
              {isEditorMode && <Button onClick={onExitEditor} className="mt-10">Cerrar Editor</Button>}

              <div className="mt-12 space-y-4 px-6 text-left">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
              </div>
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl, 
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Tu nombre..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData, isEditorMode, onExitEditor }) => {
  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Refs para el motor de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // INTERRUPTOR DE SEGURIDAD: Si falla la API una vez, se desactiva para toda la sesión.
  const apiDisabled = useRef(false);

  // Control de errores global
  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  useEffect(() => {
    if (step === 'verification' || step === 'finish') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step, currentQuestionIndex]);

  // --- MOTOR DE AUDIO ---

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const generateAudioBuffer = async (text: string, signal: AbortSignal): Promise<AudioBuffer | null> => {
    // Si ya falló antes, ni lo intentamos. Pasamos directo a fallback.
    if (apiDisabled.current) return null;

    try {
      const base64Audio = await gemini.generateSpeechBlock(text, voice);

      if (signal.aborted) return null;

      if (!base64Audio) {
         // Si la API devuelve vacío (error silencioso), activamos el interruptor
         apiDisabled.current = true;
         console.warn("API de voz falló, desactivando para el resto de la sesión.");
         return null; 
      }

      if (audioContextRef.current) {
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current, 24000, 1);
      }
    } catch (e) {
      apiDisabled.current = true;
      return null;
    }
    return null;
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES';

      const voices = window.speechSynthesis.getVoices();

      let selectedVoice = null;

      if (voice === Voice.FEMALE) {
        // CORRECCIÓN FINAL: Asignación directa de voces FEMENINAS para el botón MUJER.
        // Se prioriza 'Google español' y 'Microsoft Elena' por ser las más humanas.
        selectedVoice = voices.find(v => 
          v.name === 'Google español' || 
          v.name === 'Google Español' ||
          (v.lang.includes('es') && (
            v.name.includes('Microsoft Elena') ||
            v.name.includes('Paulina') || 
            v.name.includes('Monica') || 
            v.name.includes('Samantha') || 
            v.name.includes('Marta')
          ))
        );
      } else {
        // CORRECCIÓN FINAL: Asignación directa de voces MASCULINAS para el botón HOMBRE.
        selectedVoice = voices.find(v => 
          v.lang.includes('es') && (
            v.name.includes('Jorge') || 
            v.name.includes('Juan') || 
            v.name.includes('Pablo') ||
            v.name.includes('Diego') ||
            v.name.includes('Alvaro')
          )
        );
      }

      // Último recurso: cualquier voz en español
      if (!selectedVoice) {
         const esVoices = voices.filter(v => v.lang.startsWith('es'));
         selectedVoice = esVoices[0];
      }

      utterance.voice = selectedVoice || null;
      utterance.pitch = 1.0; 
      utterance.rate = 1.05; 

      utterance.onend = () => { resolve(); };
      utterance.onerror = () => { resolve(); };

      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  const runSequence = async (segments: { text: string, type: 'text' | 'option', key?: string, audioUrl?: string }[]) => {
    if (voice === Voice.NONE) {
      segments.forEach(seg => {
        if (seg.type === 'option' && seg.key) setVisibleOptions(prev => [...prev, seg.key!]);
      });
      return;
    }

    initAudio();
    stopAudio(); 

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    for (let i = 0; i < segments.length; i++) {
      if (signal.aborted) break;

      const segment = segments[i];
      let buffer = null;

      if (segment.audioUrl) {
        try {
          const res = await fetch(segment.audioUrl);
          const ab = await res.arrayBuffer();
          if (audioContextRef.current) {
             buffer = await audioContextRef.current.decodeAudioData(ab);
          }
        } catch (e) { buffer = null; }
      } else {
        // Aquí se decide si usar IA o fallback (si apiDisabled es true, devuelve null rápido)
        buffer = await generateAudioBuffer(segment.text, signal);
      }

      if (segment.type === 'option' && segment.key) {
        setVisibleOptions(prev => [...prev, segment.key!]);
      }

      if (buffer && !signal.aborted) {
        await playBuffer(buffer);
      } else if (!signal.aborted) {
        await nativeSpeak(segment.text);
      }
    }

    setIsSpeaking(false);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  const startSession = async () => {
    initAudio();
    setStep('verification');

    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');
    setTimeout(() => addMessage(nameQuestion, 'ia'), 500);

    await runSequence([
      { text: introText, type: 'text', audioUrl: introConfig.audioUrl },
      { text: nameQuestion, type: 'text' }
    ]);
  };

  const handleVerification = async (nameInput: string) => {
    const nameToMatch = isEditorMode ? "Coordinador" : (patientData.nombre || "");
    const inputClean = nameInput.trim().toLowerCase();
    const expectedClean = nameToMatch.split(' ')[0].toLowerCase();

    addMessage(nameInput, 'user');

    if (inputClean.includes(expectedClean) || expectedClean.includes(inputClean) || isEditorMode) {
      stopAudio();
      const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
      addMessage(welcome, 'ia');
      await runSequence([{ text: welcome, type: 'text' }]);

      setTimeout(() => {
        setStep('questionnaire');
        loadQuestion(0);
      }, 500); 
    } else {
      const errorMsg = "Parece que se ha cometido un error, este cuestionario está dirigido a otra persona. Repítame el nombre otra vez.";
      addMessage(errorMsg, 'ia');
      runSequence([{ text: errorMsg, type: 'text' }]);
    }
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${patientData.nombre || 'amigo/a'}, en breve nos volveremos a poner en contacto.`;
      addMessage(goodbye, 'ia');
      runSequence([{ text: goodbye, type: 'text' }]);
      return;
    }

    const segments: any[] = [];
    const scenarioText = q.speechScript || q.scenario;
    segments.push({ text: scenarioText, type: 'text', audioUrl: q.audioFileUrl });

    if (!q.audioFileUrl && !q.speechScript) {
      q.options.forEach(opt => {
        segments.push({ 
          text: `Opción ${opt.key.toUpperCase()}... ${opt.text}`, 
          type: 'option', 
          key: opt.key 
        });
      });
      if (index === 0) {
        segments.push({ text: "¿Con cuál de estas situaciones te sientes más identificado?", type: 'text' });
      }
    } else {
        q.options.forEach(opt => {
             setVisibleOptions(prev => [...prev, opt.key]);
        });
    }

    runSequence(segments);
  };

  const handleAnswer = async (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-16 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <h2 className={`text-3xl font-bold mb-4 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>Proceso Finalizado</h2>
              <p className={`font-black max-w-xs mx-auto text-lg uppercase tracking-tight ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Tus respuestas nos ayudarán a trazar el camino.</p>
              {isEditorMode && <Button onClick={onExitEditor} className="mt-10">Cerrar Editor</Button>}

              <div className="mt-12 space-y-4 px-6 text-left">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
              </div>
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl, 
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Tu nombre..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData, isEditorMode, onExitEditor }) => {
  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Refs para el motor de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // INTERRUPTOR DE SEGURIDAD: Si falla la API una vez, se desactiva para toda la sesión.
  const apiDisabled = useRef(false);

  // Control de errores global
  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  useEffect(() => {
    if (step === 'verification' || step === 'finish') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step, currentQuestionIndex]);

  // --- MOTOR DE AUDIO ---

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const generateAudioBuffer = async (text: string, signal: AbortSignal): Promise<AudioBuffer | null> => {
    // Si ya falló antes, ni lo intentamos. Pasamos directo a fallback.
    if (apiDisabled.current) return null;

    try {
      const base64Audio = await gemini.generateSpeechBlock(text, voice);

      if (signal.aborted) return null;

      if (!base64Audio) {
         // Si la API devuelve vacío (error silencioso), activamos el interruptor
         apiDisabled.current = true;
         console.warn("API de voz falló, desactivando para el resto de la sesión.");
         return null; 
      }

      if (audioContextRef.current) {
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current, 24000, 1);
      }
    } catch (e) {
      apiDisabled.current = true;
      return null;
    }
    return null;
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES';

      const voices = window.speechSynthesis.getVoices();

      let selectedVoice = null;

      if (voice === Voice.FEMALE) {
        // INTERCAMBIO SOLICITADO: Opción MUJER -> Busca voces MASCULINAS (Jorge, Pablo...)
        selectedVoice = voices.find(v => 
          v.lang.includes('es') && (
            v.name.includes('Jorge') || 
            v.name.includes('Juan') || 
            v.name.includes('Pablo') ||
            v.name.includes('Diego') ||
            v.name.includes('Alvaro')
          )
        );
      } else {
        // INTERCAMBIO SOLICITADO: Opción HOMBRE -> Busca voces FEMENINAS (Google español, Elena...)
        selectedVoice = voices.find(v => 
          v.name === 'Google español' || 
          v.name === 'Google Español' ||
          (v.lang.includes('es') && (
            v.name.includes('Microsoft Elena') ||
            v.name.includes('Paulina') || 
            v.name.includes('Monica') || 
            v.name.includes('Samantha') || 
            v.name.includes('Marta')
          ))
        );
      }

      // Último recurso: cualquier voz en español
      if (!selectedVoice) {
         const esVoices = voices.filter(v => v.lang.startsWith('es'));
         selectedVoice = esVoices[0];
      }

      utterance.voice = selectedVoice || null;
      utterance.pitch = 1.0; 
      utterance.rate = 1.05; 

      utterance.onend = () => { resolve(); };
      utterance.onerror = () => { resolve(); };

      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  const runSequence = async (segments: { text: string, type: 'text' | 'option', key?: string, audioUrl?: string }[]) => {
    if (voice === Voice.NONE) {
      segments.forEach(seg => {
        if (seg.type === 'option' && seg.key) setVisibleOptions(prev => [...prev, seg.key!]);
      });
      return;
    }

    initAudio();
    stopAudio(); 

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    for (let i = 0; i < segments.length; i++) {
      if (signal.aborted) break;

      const segment = segments[i];
      let buffer = null;

      if (segment.audioUrl) {
        try {
          const res = await fetch(segment.audioUrl);
          const ab = await res.arrayBuffer();
          if (audioContextRef.current) {
             buffer = await audioContextRef.current.decodeAudioData(ab);
          }
        } catch (e) { buffer = null; }
      } else {
        // Aquí se decide si usar IA o fallback (si apiDisabled es true, devuelve null rápido)
        buffer = await generateAudioBuffer(segment.text, signal);
      }

      if (segment.type === 'option' && segment.key) {
        setVisibleOptions(prev => [...prev, segment.key!]);
      }

      if (buffer && !signal.aborted) {
        await playBuffer(buffer);
      } else if (!signal.aborted) {
        await nativeSpeak(segment.text);
      }
    }

    setIsSpeaking(false);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  const startSession = async () => {
    initAudio();
    setStep('verification');

    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');
    setTimeout(() => addMessage(nameQuestion, 'ia'), 500);

    await runSequence([
      { text: introText, type: 'text', audioUrl: introConfig.audioUrl },
      { text: nameQuestion, type: 'text' }
    ]);
  };

  const handleVerification = async (nameInput: string) => {
    const nameToMatch = isEditorMode ? "Coordinador" : (patientData.nombre || "");
    const inputClean = nameInput.trim().toLowerCase();
    const expectedClean = nameToMatch.split(' ')[0].toLowerCase();

    addMessage(nameInput, 'user');

    if (inputClean.includes(expectedClean) || expectedClean.includes(inputClean) || isEditorMode) {
      stopAudio();
      const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
      addMessage(welcome, 'ia');
      await runSequence([{ text: welcome, type: 'text' }]);

      setTimeout(() => {
        setStep('questionnaire');
        loadQuestion(0);
      }, 500); 
    } else {
      const errorMsg = "Parece que se ha cometido un error, este cuestionario está dirigido a otra persona. Repítame el nombre otra vez.";
      addMessage(errorMsg, 'ia');
      runSequence([{ text: errorMsg, type: 'text' }]);
    }
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${patientData.nombre || 'amigo/a'}, en breve nos volveremos a poner en contacto.`;
      addMessage(goodbye, 'ia');
      runSequence([{ text: goodbye, type: 'text' }]);
      return;
    }

    const segments: any[] = [];
    const scenarioText = q.speechScript || q.scenario;
    segments.push({ text: scenarioText, type: 'text', audioUrl: q.audioFileUrl });

    if (!q.audioFileUrl && !q.speechScript) {
      q.options.forEach(opt => {
        segments.push({ 
          text: `Opción ${opt.key.toUpperCase()}... ${opt.text}`, 
          type: 'option', 
          key: opt.key 
        });
      });
      if (index === 0) {
        segments.push({ text: "¿Con cuál de estas situaciones te sientes más identificado?", type: 'text' });
      }
    } else {
        q.options.forEach(opt => {
             setVisibleOptions(prev => [...prev, opt.key]);
        });
    }

    runSequence(segments);
  };

  const handleAnswer = async (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-16 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <h2 className={`text-3xl font-bold mb-4 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>Proceso Finalizado</h2>
              <p className={`font-black max-w-xs mx-auto text-lg uppercase tracking-tight ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Tus respuestas nos ayudarán a trazar el camino.</p>
              {isEditorMode && <Button onClick={onExitEditor} className="mt-10">Cerrar Editor</Button>}

              <div className="mt-12 space-y-4 px-6 text-left">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
              </div>
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl, 
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Tu nombre..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData, isEditorMode, onExitEditor }) => {
  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Refs para el motor de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // INTERRUPTOR DE SEGURIDAD: Si falla la API una vez, se desactiva para toda la sesión.
  const apiDisabled = useRef(false);

  // Control de errores global
  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  useEffect(() => {
    if (step === 'verification' || step === 'finish') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step, currentQuestionIndex]);

  // --- MOTOR DE AUDIO ---

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const generateAudioBuffer = async (text: string, signal: AbortSignal): Promise<AudioBuffer | null> => {
    // Si ya falló antes, ni lo intentamos. Pasamos directo a fallback.
    if (apiDisabled.current) return null;

    try {
      const base64Audio = await gemini.generateSpeechBlock(text, voice);

      if (signal.aborted) return null;

      if (!base64Audio) {
         // Si la API devuelve vacío (error silencioso), activamos el interruptor
         apiDisabled.current = true;
         console.warn("API de voz falló, desactivando para el resto de la sesión.");
         return null; 
      }

      if (audioContextRef.current) {
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current, 24000, 1);
      }
    } catch (e) {
      apiDisabled.current = true;
      return null;
    }
    return null;
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES';

      const voices = window.speechSynthesis.getVoices();

      let selectedVoice = null;

      if (voice === Voice.FEMALE) {
        // CAMBIO SOLO AQUÍ: Botón MUJER.
        // Buscamos voces alternativas (ej: "Google Español de Estados Unidos", o Microsoft "Laura", "Sabina")
        // Evitamos explícitamente "Google español" y "Elena" porque las quieres en el botón Hombre.
        selectedVoice = voices.find(v => 
          v.lang.includes('es') && (
            v.name.includes('Estados Unidos') || // Google Español de Estados Unidos (Suele ser femenina y distinta a la de España)
            v.name.includes('Laura') ||          // Microsoft Laura
            v.name.includes('Sabina') ||         // Microsoft Sabina
            v.name.includes('Zira') ||
            v.name.includes('Helena')
          )
        );

        // Si no encuentra las específicas, busca cualquiera que NO sea las del bloque "Hombre" ni nombres masculinos
        if (!selectedVoice) {
           selectedVoice = voices.find(v => 
             v.lang.includes('es') && 
             !v.name.includes('Google español') && 
             !v.name.includes('Google Español') && 
             !v.name.includes('Elena') &&
             !v.name.includes('Jorge') && 
             !v.name.includes('Pablo')
           );
        }
      } else {
        // BOTÓN HOMBRE: MANTENIDO EXACTAMENTE IGUAL (Google español, Elena, Paulina, etc.)
        // No se ha tocado ni una coma de este bloque.
        selectedVoice = voices.find(v => 
          v.name === 'Google español' || 
          v.name === 'Google Español' ||
          (v.lang.includes('es') && (
            v.name.includes('Microsoft Elena') ||
            v.name.includes('Paulina') || 
            v.name.includes('Monica') || 
            v.name.includes('Samantha') || 
            v.name.includes('Marta')
          ))
        );
      }

      // Último recurso general si no encuentra nada específico
      if (!selectedVoice) {
         const esVoices = voices.filter(v => v.lang.startsWith('es'));
         selectedVoice = esVoices[0];
      }

      utterance.voice = selectedVoice || null;
      utterance.pitch = 1.0; 
      utterance.rate = 1.05; 

      utterance.onend = () => { resolve(); };
      utterance.onerror = () => { resolve(); };

      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  const runSequence = async (segments: { text: string, type: 'text' | 'option', key?: string, audioUrl?: string }[]) => {
    if (voice === Voice.NONE) {
      segments.forEach(seg => {
        if (seg.type === 'option' && seg.key) setVisibleOptions(prev => [...prev, seg.key!]);
      });
      return;
    }

    initAudio();
    stopAudio(); 

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    for (let i = 0; i < segments.length; i++) {
      if (signal.aborted) break;

      const segment = segments[i];
      let buffer = null;

      if (segment.audioUrl) {
        try {
          const res = await fetch(segment.audioUrl);
          const ab = await res.arrayBuffer();
          if (audioContextRef.current) {
             buffer = await audioContextRef.current.decodeAudioData(ab);
          }
        } catch (e) { buffer = null; }
      } else {
        // Aquí se decide si usar IA o fallback (si apiDisabled es true, devuelve null rápido)
        buffer = await generateAudioBuffer(segment.text, signal);
      }

      if (segment.type === 'option' && segment.key) {
        setVisibleOptions(prev => [...prev, segment.key!]);
      }

      if (buffer && !signal.aborted) {
        await playBuffer(buffer);
      } else if (!signal.aborted) {
        await nativeSpeak(segment.text);
      }
    }

    setIsSpeaking(false);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  const startSession = async () => {
    initAudio();
    setStep('verification');

    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');
    setTimeout(() => addMessage(nameQuestion, 'ia'), 500);

    await runSequence([
      { text: introText, type: 'text', audioUrl: introConfig.audioUrl },
      { text: nameQuestion, type: 'text' }
    ]);
  };

  const handleVerification = async (nameInput: string) => {
    const nameToMatch = isEditorMode ? "Coordinador" : (patientData.nombre || "");
    const inputClean = nameInput.trim().toLowerCase();
    const expectedClean = nameToMatch.split(' ')[0].toLowerCase();

    addMessage(nameInput, 'user');

    if (inputClean.includes(expectedClean) || expectedClean.includes(inputClean) || isEditorMode) {
      stopAudio();
      const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
      addMessage(welcome, 'ia');
      await runSequence([{ text: welcome, type: 'text' }]);

      setTimeout(() => {
        setStep('questionnaire');
        loadQuestion(0);
      }, 500); 
    } else {
      const errorMsg = "Parece que se ha cometido un error, este cuestionario está dirigido a otra persona. Repítame el nombre otra vez.";
      addMessage(errorMsg, 'ia');
      runSequence([{ text: errorMsg, type: 'text' }]);
    }
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${patientData.nombre || 'amigo/a'}, en breve nos volveremos a poner en contacto.`;
      addMessage(goodbye, 'ia');
      runSequence([{ text: goodbye, type: 'text' }]);
      return;
    }

    const segments: any[] = [];
    const scenarioText = q.speechScript || q.scenario;
    segments.push({ text: scenarioText, type: 'text', audioUrl: q.audioFileUrl });

    if (!q.audioFileUrl && !q.speechScript) {
      q.options.forEach(opt => {
        segments.push({ 
          text: `Opción ${opt.key.toUpperCase()}... ${opt.text}`, 
          type: 'option', 
          key: opt.key 
        });
      });
      if (index === 0) {
        segments.push({ text: "¿Con cuál de estas situaciones te sientes más identificado?", type: 'text' });
      }
    } else {
        q.options.forEach(opt => {
             setVisibleOptions(prev => [...prev, opt.key]);
        });
    }

    runSequence(segments);
  };

  const handleAnswer = async (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-16 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <h2 className={`text-3xl font-bold mb-4 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>Proceso Finalizado</h2>
              <p className={`font-black max-w-xs mx-auto text-lg uppercase tracking-tight ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Tus respuestas nos ayudarán a trazar el camino.</p>
              {isEditorMode && <Button onClick={onExitEditor} className="mt-10">Cerrar Editor</Button>}

              <div className="mt-12 space-y-4 px-6 text-left">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
              </div>
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl, 
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Tu nombre..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

export interface CoordinatorProfile {
  nombre: string;
  email: string;
}

export interface AuthUser {
  email: string;
  pin: string; // 4 a 6 dígitos
  nombre: string;
  securityQuestion: string;
  securityAnswer: string;
}

export interface PatientData {
  id: string;
  nombre: string;
  edad: string;
  sexo: string;
  observaciones: string;
  telefono: string;
  email: string;
  status: 'pending' | 'completed' | 'waiting';
  answers?: Record<string, string>;
  conversationSummary?: string;
}

export interface Question {
  id: string;
  scenario: string;
  options: {
    key: string;
    text: string;
  }[];
  speechScript?: string;
  audioFileUrl?: string; // Nuevo campo para MP3 personalizado
  isScale?: boolean;
  scaleLabel?: string;
  followUp?: string;
}

export enum Voice {
  MALE = 'Kore',   // Voz grave y calmada
  FEMALE = 'Aoede', // Voz aguda y profesional
  NONE = 'none'
}

export type View = 'COORDINATOR' | 'PATIENT_SESSION' | 'LANDING';

import React, { useState, useEffect } from 'react';
import { CoordinatorDashboard } from './components/CoordinatorDashboard';
import { PatientInterface } from './components/PatientInterface';
import { View, PatientData, CoordinatorProfile, AuthUser } from './types';
import { Button, Logo, Input, Card, Toast } from './components/UI';

// Credenciales Maestras
const MASTER_USER = {
  email: 'cuestionarioespejo@gmail.com',
  pin: '66099',
  nombre: 'Administrador Maestro'
};

const App: React.FC = () => {
  const [view, setView] = useState<View>('LANDING');
  const [patientData, setPatientData] = useState<Partial<PatientData>>({});
  const [coordinator, setCoordinator] = useState<CoordinatorProfile | null>(null);
  const [isEditorMode, setIsEditorMode] = useState(false);

  // Estados de Autenticación
  const [authStep, setAuthStep] = useState<'EMAIL' | 'LOGIN_PIN' | 'REGISTER' | 'RECOVERY' | 'RESET_PIN'>('EMAIL');
  const [emailInput, setEmailInput] = useState('');
  const [pinInput, setPinInput] = useState('');
  const [toast, setToast] = useState({ show: false, msg: '' });

  // Estado para Registro / Recuperación
  const [regForm, setRegForm] = useState({
    nombre: '',
    pin: '',
    confirmPin: '',
    question: '',
    answer: ''
  });
  const [recoveryAnswer, setRecoveryAnswer] = useState('');
  const [currentUserData, setCurrentUserData] = useState<AuthUser | null>(null);

  useEffect(() => {
    const authStatus = localStorage.getItem('radar_auth') === 'true';
    const savedProfile = localStorage.getItem('radar_coordinator');
    if (authStatus && savedProfile) {
      setCoordinator(JSON.parse(savedProfile));
      setView('COORDINATOR');
    }

    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/session')) {
        const params = new URLSearchParams(hash.split('?')[1]);
        const pEncoded = params.get('p');
        if (pEncoded) {
          try {
            const decoded = JSON.parse(atob(pEncoded));
            setPatientData(decoded);
            setIsEditorMode(false);
            setView('PATIENT_SESSION');
          } catch (e) {
            console.error("Link de sesión no válido");
            setView('LANDING');
          }
        }
      } else if (hash === '#/coordinator') {
        if (localStorage.getItem('radar_auth') === 'true') {
          setView('COORDINATOR');
        } else {
          setView('LANDING');
          setAuthStep('EMAIL');
          window.location.hash = '';
        }
      } else if (!hash) {
        setView('LANDING');
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const showToast = (msg: string) => {
    setToast({ show: true, msg });
  };

  const getUsers = (): Record<string, AuthUser> => {
    return JSON.parse(localStorage.getItem('radar_users_db') || '{}');
  };

  const saveUser = (user: AuthUser) => {
    const db = getUsers();
    db[user.email] = user;
    localStorage.setItem('radar_users_db', JSON.stringify(db));
  };

  // --- Lógica de Auth ---

  const handleEmailSubmit = () => {
    if (!emailInput.includes('@') || !emailInput.includes('.')) {
      return showToast("Introduce un email válido");
    }

    const normalizedEmail = emailInput.trim().toLowerCase();

    if (normalizedEmail === MASTER_USER.email) {
      setAuthStep('LOGIN_PIN');
      return;
    }

    const db = getUsers();
    if (db[normalizedEmail]) {
      setCurrentUserData(db[normalizedEmail]);
      setAuthStep('LOGIN_PIN');
    } else {
      setAuthStep('REGISTER');
    }
  };

  const handlePinLogin = () => {
    const normalizedEmail = emailInput.trim().toLowerCase();

    // Verificación Maestra
    if (normalizedEmail === MASTER_USER.email) {
      if (pinInput === MASTER_USER.pin) {
        loginSuccess(MASTER_USER.nombre, MASTER_USER.email);
      } else {
        showToast("PIN Maestro incorrecto");
      }
      return;
    }

    // Verificación Usuario Normal
    if (currentUserData) {
      if (pinInput === currentUserData.pin) {
        loginSuccess(currentUserData.nombre, currentUserData.email);
      } else {
        showToast("PIN incorrecto");
      }
    }
  };

  const handleRegister = () => {
    const { nombre, pin, confirmPin, question, answer } = regForm;

    if (!nombre || !pin || !question || !answer) return showToast("Todos los campos son obligatorios");
    if (!/^\d{4,6}$/.test(pin)) return showToast("El PIN debe tener entre 4 y 6 dígitos numéricos");
    if (pin !== confirmPin) return showToast("Los PIN no coinciden");

    const newUser: AuthUser = {
      email: emailInput.trim().toLowerCase(),
      nombre,
      pin,
      securityQuestion: question,
      securityAnswer: answer.trim().toLowerCase()
    };

    saveUser(newUser);
    showToast("Registro completado con éxito");
    loginSuccess(newUser.nombre, newUser.email);
  };

  const handleRecoveryCheck = () => {
    if (!currentUserData) return;
    if (recoveryAnswer.trim().toLowerCase() === currentUserData.securityAnswer) {
      setAuthStep('RESET_PIN');
      setRegForm({ ...regForm, pin: '', confirmPin: '' }); // Reusamos regForm para el nuevo pin
    } else {
      showToast("Respuesta incorrecta");
    }
  };

  const handleResetPin = () => {
    if (!currentUserData) return;
    const { pin, confirmPin } = regForm;
    if (!/^\d{4,6}$/.test(pin)) return showToast("El PIN debe tener entre 4 y 6 dígitos");
    if (pin !== confirmPin) return showToast("Los PIN no coinciden");

    const updatedUser = { ...currentUserData, pin };
    saveUser(updatedUser);
    setCurrentUserData(updatedUser);
    showToast("PIN actualizado correctamente");
    setAuthStep('LOGIN_PIN');
    setPinInput('');
  };

  const loginSuccess = (nombre: string, email: string) => {
    const profile = { nombre, email };
    localStorage.setItem('radar_auth', 'true');
    localStorage.setItem('radar_coordinator', JSON.stringify(profile));
    setCoordinator(profile);
    setView('COORDINATOR');
    window.location.hash = '#/coordinator';

    // Limpiar estados
    setEmailInput('');
    setPinInput('');
    setRegForm({ nombre: '', pin: '', confirmPin: '', question: '', answer: '' });
  };

  const handleLogout = () => {
    localStorage.removeItem('radar_auth');
    localStorage.removeItem('radar_coordinator');
    setCoordinator(null);
    setView('LANDING');
    setAuthStep('EMAIL');
    setEmailInput('');
    setPinInput('');
    window.location.hash = '';
  };

  const enterEditMode = () => {
    setIsEditorMode(true);
    setView('PATIENT_SESSION');
  };

  return (
    <div className="min-h-screen text-slate-800 bg-slate-50/10 overflow-x-hidden overflow-y-auto font-sans">
      {view === 'LANDING' && (
        <div className="min-h-screen flex items-center justify-center flex-col p-6 text-center space-y-8 animate-in fade-in duration-1000 pb-20">
           <div className="max-w-xl w-full">
             <Logo />

             {authStep === 'EMAIL' && (
               <Card className="mt-12 animate-in zoom-in-95 duration-500">
                 <h3 className="text-2xl font-bold text-blue-900 mb-6">Acceso Coordinador</h3>
                 <p className="text-sm text-slate-500 mb-6">Introduce tu correo electrónico para identificarte o registrarte.</p>
                 <Input 
                   label="Correo Electrónico" 
                   type="email" 
                   value={emailInput} 
                   onChange={e => setEmailInput(e.target.value)} 
                   placeholder="ejemplo@correo.com"
                   onKeyPress={e => e.key === 'Enter' && handleEmailSubmit()}
                 />
                 <Button className="w-full mt-4" onClick={handleEmailSubmit}>Continuar</Button>
               </Card>
             )}

             {authStep === 'LOGIN_PIN' && (
               <Card className="mt-12 animate-in slide-in-from-right-8 duration-500">
                 <div className="flex justify-between items-center mb-6">
                   <button onClick={() => setAuthStep('EMAIL')} className="text-xs text-blue-500 font-bold hover:underline"><i className="fas fa-arrow-left"></i> Cambiar usuario</button>
                   <div className="text-[10px] font-black bg-blue-50 text-blue-600 px-2 py-1 rounded">{emailInput}</div>
                 </div>
                 <h3 className="text-xl font-bold text-blue-900 mb-2">Introduce tu PIN</h3>
                 <p className="text-xs text-slate-400 mb-6">Clave de acceso de 4 a 6 dígitos.</p>

                 <Input 
                   label="PIN de Acceso" 
                   type="password" 
                   maxLength={6}
                   placeholder="****"
                   value={pinInput} 
                   onChange={e => setPinInput(e.target.value.replace(/\D/g, ''))} 
                   onKeyPress={e => e.key === 'Enter' && handlePinLogin()}
                 />

                 <Button className="w-full mt-2" onClick={handlePinLogin}>Entrar</Button>

                 {emailInput !== MASTER_USER.email && (
                   <button 
                     onClick={() => { setRecoveryAnswer(''); setAuthStep('RECOVERY'); }} 
                     className="mt-6 text-xs text-slate-400 hover:text-blue-600 font-bold transition-colors"
                   >
                     ¿Olvidaste tu clave?
                   </button>
                 )}
               </Card>
             )}

             {authStep === 'REGISTER' && (
               <Card className="mt-8 animate-in slide-in-from-right-8 duration-500 text-left">
                  <div className="flex items-center gap-2 mb-6 border-b border-slate-100 pb-4">
                    <button onClick={() => setAuthStep('EMAIL')} className="text-slate-400 hover:text-blue-600 transition-colors"><i className="fas fa-arrow-left"></i></button>
                    <h3 className="text-xl font-bold text-blue-900">Crear Nueva Cuenta</h3>
                  </div>

                  <div className="space-y-4">
                    <div className="p-3 bg-blue-50 rounded-xl mb-4">
                      <p className="text-[10px] uppercase font-black text-blue-500">Registrando:</p>
                      <p className="text-sm font-bold text-blue-900">{emailInput}</p>
                    </div>

                    <Input label="Tu Nombre (Visible en Dashboard)" value={regForm.nombre} onChange={e => setRegForm({...regForm, nombre: e.target.value})} placeholder="Ej: Dr. García" />

                    <div className="grid grid-cols-2 gap-4">
                      <Input label="Crear PIN (4-6 dígitos)" type="password" maxLength={6} value={regForm.pin} onChange={e => setRegForm({...regForm, pin: e.target.value.replace(/\D/g, '')})} placeholder="****" />
                      <Input label="Confirmar PIN" type="password" maxLength={6} value={regForm.confirmPin} onChange={e => setRegForm({...regForm, confirmPin: e.target.value.replace(/\D/g, '')})} placeholder="****" />
                    </div>

                    <div className="pt-4 border-t border-slate-100">
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Recuperación de Cuenta</p>
                      <Input label="Pregunta de Seguridad" value={regForm.question} onChange={e => setRegForm({...regForm, question: e.target.value})} placeholder="Ej: ¿Nombre de mi primera mascota?" />
                      <Input label="Respuesta" value={regForm.answer} onChange={e => setRegForm({...regForm, answer: e.target.value})} placeholder="Tu respuesta secreta" />
                    </div>

                    <Button className="w-full py-4 mt-2" onClick={handleRegister}>Registrar y Acceder</Button>
                  </div>
               </Card>
             )}

            {authStep === 'RECOVERY' && currentUserData && (
               <Card className="mt-12 animate-in slide-in-from-right-8 duration-500">
                 <div className="flex justify-start mb-6">
                   <button onClick={() => setAuthStep('LOGIN_PIN')} className="text-xs text-blue-500 font-bold hover:underline"><i className="fas fa-arrow-left"></i> Volver</button>
                 </div>
                 <h3 className="text-xl font-bold text-blue-900 mb-4">Recuperar Acceso</h3>
                 <div className="bg-amber-50 p-4 rounded-xl border border-amber-100 mb-6 text-left">
                    <p className="text-[10px] font-black text-amber-600 uppercase mb-1">Pregunta de Seguridad:</p>
                    <p className="text-sm font-bold text-amber-900">{currentUserData.securityQuestion}</p>
                 </div>

                 <Input 
                   label="Tu Respuesta" 
                   value={recoveryAnswer} 
                   onChange={e => setRecoveryAnswer(e.target.value)} 
                   placeholder="Escribe tu respuesta..."
                 />

                 <Button className="w-full mt-4" onClick={handleRecoveryCheck}>Verificar</Button>
               </Card>
             )}

             {authStep === 'RESET_PIN' && (
               <Card className="mt-12 animate-in slide-in-from-right-8 duration-500">
                 <h3 className="text-xl font-bold text-blue-900 mb-6">Establecer Nuevo PIN</h3>
                 <Input label="Nuevo PIN (4-6 dígitos)" type="password" maxLength={6} value={regForm.pin} onChange={e => setRegForm({...regForm, pin: e.target.value.replace(/\D/g, '')})} placeholder="****" />
                 <Input label="Confirmar Nuevo PIN" type="password" maxLength={6} value={regForm.confirmPin} onChange={e => setRegForm({...regForm, confirmPin: e.target.value.replace(/\D/g, '')})} placeholder="****" />
                 <Button className="w-full mt-6" onClick={handleResetPin}>Guardar Nuevo PIN</Button>
               </Card>
             )}

           </div>
        </div>
      )}

      {view === 'COORDINATOR' && coordinator && (
        <CoordinatorDashboard 
          profile={coordinator} 
          onLogout={handleLogout} 
          onEnterEditMode={enterEditMode}
        />
      )}

      {view === 'PATIENT_SESSION' && (
        <PatientInterface 
          patientData={patientData} 
          isEditorMode={isEditorMode}
          onExitEditor={() => {
            setIsEditorMode(false);
            setView('COORDINATOR');
            window.location.hash = '#/coordinator';
          }}
        />
      )}

      <Toast message={toast.msg} visible={toast.show} onHide={() => setToast({ ...toast, show: false })} />
    </div>
  );
};

