    }

    if (sendMethods.email) {
      // USAMOS ENLACE DIRECTO A GMAIL WEB (Composer)
      // Esto abre la ventana de redacción de Gmail del usuario logueado en el navegador
      // Soluciona el problema de "simulación" de mailto y usa su cuenta real.
      const gmailUrl = `https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(patient.email)}&su=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
