              <div className="space-y-4">
                <div className="flex items-center gap-4 p-4 bg-gradient-to-br from-teal-50 to-white rounded-2xl border border-teal-100/50">
                  <div className="w-14 h-14 bg-blue-900 text-white rounded-2xl flex items-center justify-center text-xl font-black shadow-lg shadow-blue-900/20">
                    {profile.nombre.charAt(0)}
