                  <h3 className="font-black text-[10px] uppercase text-slate-400 tracking-widest">Actividad Reciente</h3>
                  <span className="text-[10px] bg-slate-100 px-2 py-0.5 rounded-full text-slate-500">{registry.length} totales</span>
                </div>
                <div className="space-y-3">
                  {registry.length === 0 ? (
                    <p className="text-xs text-slate-400 text-center py-4 italic">No hay registros aún</p>
                  ) : (
                    registry.slice(-10).reverse().map((p) => (
                      <div key={p.id} className="group relative flex justify-between items-center p-3 bg-white/80 rounded-xl border border-slate-100 hover:border-teal-200 transition-all shadow-sm">
                        <div className="flex flex-col overflow-hidden">
