                    <label className="flex items-center gap-2 cursor-pointer bg-white px-3 py-2 rounded-xl border border-slate-200 hover:border-teal-300 transition-all">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded text-teal-600 focus:ring-teal-500"
