import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2 mb-3`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

// Estructura para almacenar el audio precargado de una "escena" completa
interface PreloadedScene {
  scenarioBuffer: AudioBuffer | null;
  optionsBuffers: { key: string, buffer: AudioBuffer | null }[];
  closingBuffer: AudioBuffer | null;
}

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData: initialPatientData, isEditorMode, onExitEditor }) => {
  // Estado local para datos del paciente (mutable si corrige el nombre)
  const [currentPatientData, setCurrentPatientData] = useState(initialPatientData);

  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'loading' | 'intro' | 'verification' | 'questionnaire' | 'finish'>('loading');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados para informe
  const [clinicalReport, setClinicalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isPreloading, setIsPreloading] = useState(false); // Nuevo estado para indicar carga de audio
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Lógica de verificación
  const [verificationAttempts, setVerificationAttempts] = useState(0);

  // Refs de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);

  // Cache para la intro precargada
  const introBufferRef = useRef<AudioBuffer | null>(null);
  const nameQuestionBufferRef = useRef<AudioBuffer | null>(null);

  // Interruptor de seguridad API
  const apiDisabled = useRef(false);

  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  // Inicializar AudioContext y Precargar Intro al montar
  useEffect(() => {
    const initAndPreload = async () => {
      // 1. Init Context
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      // 2. Preload Intro
      if (!isEditorMode) {
        const introTxt = introConfig.text;
        const nameQTxt = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

        // Paralelizar descargas
        const [introB, nameQB] = await Promise.all([
           fetchAudioBuffer(introTxt, introConfig.audioUrl),
           fetchAudioBuffer(nameQTxt)
        ]);

        introBufferRef.current = introB;
        nameQuestionBufferRef.current = nameQB;
      }
      setStep('intro');
    };
    initAndPreload();
  }, [introConfig, isEditorMode]); // Dependencias para recargar si cambia config

  // Efecto reporte final
  useEffect(() => {
    if (step === 'finish' && !clinicalReport && !isEditorMode) {
      generateClinicalReport();
    }
  }, [step]);

  // Scroll automático
  useEffect(() => {
    if (step === 'verification') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step]);

  // --- SERVICIOS AUXILIARES ---

  const generateClinicalReport = async () => {
    setIsGeneratingReport(true);
    const context = transcript.map(t => `${t.sender}: ${t.text}`).join('\n');
    const summary = await gemini.summarizeSession(currentPatientData, answers, context);
    setClinicalReport(summary);
    setIsGeneratingReport(false);
  };

  const sendResultsToCoordinator = () => {
    if (!currentPatientData.coordinatorEmail && !isEditorMode) {
      alert("No se ha encontrado el email del coordinador. Por favor, toma una captura de pantalla.");
      return;
    }

    const email = currentPatientData.coordinatorEmail || 'cuestionarioespejo@gmail.com';
    const subject = `RESULTADOS: ${currentPatientData.nombre || 'Paciente'} - Cuestionario Espejo`;

    const body = `INFORME DE SESIÓN - CUESTIONARIO ESPEJO
------------------------------------------------
PACIENTE (REGISTRADO): ${initialPatientData.nombre || 'N/A'}
PACIENTE (ACTUAL): ${currentPatientData.nombre || 'N/A'}
EDAD: ${currentPatientData.edad || 'N/A'}
FECHA: ${new Date().toLocaleDateString()}
------------------------------------------------

VALORACIÓN IA (GEMINI):
${clinicalReport}

------------------------------------------------
RESPUESTAS CRUDAS:
${Object.entries(answers).map(([qid, ans]) => `P${qid}: ${ans}`).join('\n')}

------------------------------------------------
Fin del reporte.`;

    window.location.href = `mailto:${email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  };

  // --- MOTOR DE AUDIO (CORE) ---

  const fetchAudioBuffer = async (text: string, customUrl?: string): Promise<AudioBuffer | null> => {
    if (voice === Voice.NONE) return null;
    if (apiDisabled.current && !customUrl) return null;

    try {
      if (customUrl) {
        const res = await fetch(customUrl);
        const ab = await res.arrayBuffer();
        return await audioContextRef.current!.decodeAudioData(ab);
      } else {
        // Usamos la voz configurada actualmente
        const base64Audio = await gemini.generateSpeechBlock(text, voice);
        if (!base64Audio) return null;
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current!, 24000, 1);
      }
    } catch (e) {
      console.error("Error generating audio", e);
      return null;
    }
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }
      if (audioContextRef.current.state === 'suspended') audioContextRef.current.resume();

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        setIsSpeaking(false);
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES';
      // Lógica de fallback simplificada
      utterance.onend = () => { setIsSpeaking(false); resolve(); };
      utterance.onerror = () => { setIsSpeaking(false); resolve(); };
      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  // --- LOGICA DE PRECARGA DE PREGUNTAS ---

  const playQuestionSequence = async (q: Question) => {
    setIsPreloading(true);
    setVisibleOptions([]);

    // 1. PRECARGA PARALELA
    const promises: Promise<any>[] = [];

    // Escenario
    const scenarioText = q.speechScript || q.scenario;
    promises.push(fetchAudioBuffer(scenarioText, q.audioFileUrl)); // Index 0

    // Opciones
    q.options.forEach(opt => {
      const text = `Opción ${opt.key.toUpperCase()}... ${opt.text}`;
      promises.push(fetchAudioBuffer(text));
    });

    // Pregunta de cierre (si no hay audio custom)
    let closingIndex = -1;
    if (!q.audioFileUrl && !q.speechScript) {
      const closingText = "¿Con cuál de estas situaciones te sientes más identificado?";
      promises.push(fetchAudioBuffer(closingText));
      closingIndex = promises.length - 1; // Última promesa
    }

    const buffers = await Promise.all(promises);
    setIsPreloading(false);

    // 2. REPRODUCCION SECUENCIAL SIN PAUSAS
    // Escenario
    if (buffers[0]) await playBuffer(buffers[0]);
    else await nativeSpeak(scenarioText);

    // Opciones (Sincronizadas: Muestro -> Sueno)
    for (let i = 0; i < q.options.length; i++) {
      const opt = q.options[i];
      const buff = buffers[i + 1]; // Offset por el escenario

      setVisibleOptions(prev => [...prev, opt.key]); // MOSTRAR AL INSTANTE QUE VA A SONAR

      if (buff) await playBuffer(buff);
      else await nativeSpeak(`Opción ${opt.key}... ${opt.text}`);
    }

    // Cierre
    if (closingIndex !== -1) {
      const closingBuff = buffers[closingIndex];
      if (closingBuff) await playBuffer(closingBuff);
      else await nativeSpeak("¿Con cuál de estas situaciones te sientes más identificado?");
    }
  };

  // --- FLUJO DE SESION ---

  const startSession = async () => {
    if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();

    setStep('verification');
    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');

    // Reproducir Intro Precargada
    if (introBufferRef.current) await playBuffer(introBufferRef.current);
    else await nativeSpeak(introText);

    // Pregunta Nombre
    addMessage(nameQuestion, 'ia');
    if (nameQuestionBufferRef.current) await playBuffer(nameQuestionBufferRef.current);
    else await nativeSpeak(nameQuestion);
  };

  const handleVerification = async (nameInput: string) => {
    const inputClean = nameInput.trim();
    addMessage(nameInput, 'user');

    if (verificationAttempts === 0) {
        // PRIMER INTENTO: Comprobación contra registro
        const nameToMatch = isEditorMode ? "Coordinador" : (currentPatientData.nombre || "");
        const inputLower = inputClean.toLowerCase();
        const expectedLower = nameToMatch.split(' ')[0].toLowerCase();

        if (inputLower.includes(expectedLower) || expectedLower.includes(inputLower) || isEditorMode) {
            // COINCIDE
            proceedToQuestionnaire();
        } else {
            // NO COINCIDE
            const mismatchMsg = `El nombre no coincide con nuestros registros (${currentPatientData.nombre}). Por favor, escribe el nombre completo por el que quieres ser conocido en los informes y pulsa Confirmar.`;
            setVerificationAttempts(1);
            addMessage(mismatchMsg, 'ia');

            // Generar audio al vuelo para el error (caso borde)
            const errorBuff = await fetchAudioBuffer(mismatchMsg);
            if (errorBuff) await playBuffer(errorBuff);
            else await nativeSpeak(mismatchMsg);
        }
    } else {
        // SEGUNDO INTENTO: Aceptamos el nuevo nombre
        setCurrentPatientData({ ...currentPatientData, nombre: inputClean });
        const acceptedMsg = `Entendido, actualizamos tu ficha como "${inputClean}". Comenzamos el cuestionario.`;
        addMessage(acceptedMsg, 'ia');

        const accBuff = await fetchAudioBuffer(acceptedMsg);
        if (accBuff) await playBuffer(accBuff);
        else await nativeSpeak(acceptedMsg);

        setTimeout(proceedToQuestionnaire, 500);
    }
  };

  const proceedToQuestionnaire = async () => {
    stopAudio();
    const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
    addMessage(welcome, 'ia');

    // Play welcome simple
    const b = await fetchAudioBuffer(welcome);
    if (b) await playBuffer(b);
    else await nativeSpeak(welcome);

    setStep('questionnaire');
    loadQuestion(0);
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${currentPatientData.nombre?.split(' ')[0] || 'amigo/a'}, en breve nos volveremos a poner en contacto para ofrecerte una hoja de ruta.`;
      addMessage(goodbye, 'ia');
      const b = await fetchAudioBuffer(goodbye);
      if (b) await playBuffer(b);
      else await nativeSpeak(goodbye);
      return;
    }

    playQuestionSequence(q);
  };

  const handleAnswer = (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  // --- UI RENDER ---

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  // --- EDITOR LOGIC (Sin cambios mayores) ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  if (step === 'loading') {
    return <div className="min-h-screen flex items-center justify-center bg-slate-50"><div className="animate-spin w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full"></div></div>;
  }

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>

              {isPreloading && (
                <div className="absolute top-4 right-6 flex items-center gap-2">
                    <div className="w-4 h-4 border-2 border-blue-400 border-t-transparent rounded-full animate-spin"></div>
                    <span className="text-[10px] uppercase font-black opacity-50">Cargando Audio...</span>
                </div>
              )}

              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-12 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <div className="mb-8">
                 <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-3xl mx-auto mb-4 animate-in zoom-in duration-500">
                    <i className="fas fa-check"></i>
                 </div>
                 <h2 className={`text-2xl font-bold mb-2 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>¡Gracias {currentPatientData.nombre?.split(' ')[0]}!</h2>
                 <p className={`font-medium max-w-xs mx-auto text-sm opacity-80 ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Has completado tu primer paso con valentía.</p>
              </div>

              {isGeneratingReport ? (
                <div className="flex flex-col items-center gap-4 py-6">
                   <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                   <p className="text-xs font-black uppercase text-blue-500 animate-pulse">Generando Informe IA...</p>
                </div>
              ) : (
                <div className="px-6 pb-8 animate-in slide-in-from-bottom-4">
                   <p className="text-xs text-slate-400 mb-6">Tus respuestas y la valoración del Radar están listas para ser enviadas a tu coordinador.</p>
                   <Button onClick={sendResultsToCoordinator} className="w-full py-4 text-lg shadow-xl shadow-green-500/20 bg-green-600 hover:bg-green-700">
                     <i className="fas fa-paper-plane mr-2"></i> Enviar Resultados al Profesional
                   </Button>
                   <p className="text-[9px] text-slate-400 mt-4 max-w-[250px] mx-auto">Al pulsar, se abrirá tu aplicación de correo para enviar el informe generado.</p>
                </div>
              )}

              {isEditorMode && <Button onClick={onExitEditor} variant="outline" className="mt-4 mx-6">Salir del Editor</Button>}
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl, 
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder={verificationAttempts === 0 ? "Tu nombre..." : "Nombre correcto..."} className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2 mb-3`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

// Estructura para almacenar el audio precargado de una "escena" completa
interface PreloadedScene {
  scenarioBuffer: AudioBuffer | null;
  optionsBuffers: { key: string, buffer: AudioBuffer | null }[];
  closingBuffer: AudioBuffer | null;
}

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData: initialPatientData, isEditorMode, onExitEditor }) => {
  // Estado local para datos del paciente (mutable si corrige el nombre)
  const [currentPatientData, setCurrentPatientData] = useState(initialPatientData);

  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'loading' | 'intro' | 'verification' | 'questionnaire' | 'finish'>('loading');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.MALE); 
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados para informe
  const [clinicalReport, setClinicalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isPreloading, setIsPreloading] = useState(false); // Nuevo estado para indicar carga de audio
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Lógica de verificación
  const [verificationAttempts, setVerificationAttempts] = useState(0);

  // Refs de audio
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);

  // Cache para la intro precargada
  const introBufferRef = useRef<AudioBuffer | null>(null);
  const nameQuestionBufferRef = useRef<AudioBuffer | null>(null);

  // Interruptor de seguridad API
  const apiDisabled = useRef(false);

  useEffect(() => {
    const handleError = (e: any) => e.preventDefault();
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', (e) => e.preventDefault());
    return () => window.removeEventListener('error', handleError);
  }, []);

  // Inicializar AudioContext y Precargar Intro al montar
  useEffect(() => {
    const initAndPreload = async () => {
      // 1. Init Context
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      // 2. Preload Intro
      if (!isEditorMode) {
        const introTxt = introConfig.text;
        const nameQTxt = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

        // Paralelizar descargas
        const [introB, nameQB] = await Promise.all([
           fetchAudioBuffer(introTxt, introConfig.audioUrl),
           fetchAudioBuffer(nameQTxt)
        ]);

        introBufferRef.current = introB;
        nameQuestionBufferRef.current = nameQB;
      }
      setStep('intro');
    };
    initAndPreload();
  }, [introConfig, isEditorMode]); // Dependencias para recargar si cambia config

  // Efecto reporte final
  useEffect(() => {
    if (step === 'finish' && !clinicalReport && !isEditorMode) {
      generateClinicalReport();
    }
  }, [step]);

  // Scroll automático
  useEffect(() => {
    if (step === 'verification') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step]);

  // --- SERVICIOS AUXILIARES ---

  const generateClinicalReport = async () => {
    setIsGeneratingReport(true);
    const context = transcript.map(t => `${t.sender}: ${t.text}`).join('\n');
    const summary = await gemini.summarizeSession(currentPatientData, answers, context);
    setClinicalReport(summary);
    setIsGeneratingReport(false);
  };

  const sendResultsToCoordinator = () => {
    if (!currentPatientData.coordinatorEmail && !isEditorMode) {
      alert("No se ha encontrado el email del coordinador. Por favor, toma una captura de pantalla.");
      return;
    }

    const email = currentPatientData.coordinatorEmail || 'cuestionarioespejo@gmail.com';
    const subject = `RESULTADOS: ${currentPatientData.nombre || 'Paciente'} - Cuestionario Espejo`;

    const body = `INFORME DE SESIÓN - CUESTIONARIO ESPEJO
------------------------------------------------
PACIENTE (REGISTRADO): ${initialPatientData.nombre || 'N/A'}
PACIENTE (ACTUAL): ${currentPatientData.nombre || 'N/A'}
EDAD: ${currentPatientData.edad || 'N/A'}
FECHA: ${new Date().toLocaleDateString()}
------------------------------------------------

VALORACIÓN IA (GEMINI):
${clinicalReport}

------------------------------------------------
RESPUESTAS CRUDAS:
${Object.entries(answers).map(([qid, ans]) => `P${qid}: ${ans}`).join('\n')}

------------------------------------------------
Fin del reporte.`;

    window.location.href = `mailto:${email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  };

  // --- MOTOR DE AUDIO (CORE) ---

  const fetchAudioBuffer = async (text: string, customUrl?: string): Promise<AudioBuffer | null> => {
    if (voice === Voice.NONE) return null;
    if (apiDisabled.current && !customUrl) return null;

    try {
      if (customUrl) {
        const res = await fetch(customUrl);
        const ab = await res.arrayBuffer();
        return await audioContextRef.current!.decodeAudioData(ab);
      } else {
        // Usamos la voz configurada actualmente
        const base64Audio = await gemini.generateSpeechBlock(text, voice);
        if (!base64Audio) return null;
        const bytes = gemini.decodeBase64(base64Audio);
        return await gemini.decodeAudioData(bytes, audioContextRef.current!, 24000, 1);
      }
    } catch (e) {
      console.error("Error generating audio", e);
      return null;
    }
  };

  const playBuffer = (buffer: AudioBuffer) => {
    return new Promise<void>((resolve) => {
      if (!audioContextRef.current) { resolve(); return; }
      if (audioContextRef.current.state === 'suspended') audioContextRef.current.resume();

      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      activeSourceRef.current = source;

      source.onended = () => {
        setIsSpeaking(false);
        resolve();
      };

      setIsSpeaking(true);
      source.start();
    });
  };

  const nativeSpeak = (text: string) => {
    return new Promise<void>((resolve) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'es-ES';
      // Lógica de fallback simplificada
      utterance.onend = () => { setIsSpeaking(false); resolve(); };
      utterance.onerror = () => { setIsSpeaking(false); resolve(); };
      setIsSpeaking(true);
      window.speechSynthesis.speak(utterance);
    });
  };

  const stopAudio = () => {
    if (activeSourceRef.current) {
      try { activeSourceRef.current.stop(); } catch (e) {}
      activeSourceRef.current = null;
    }
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  // --- LOGICA DE PRECARGA DE PREGUNTAS ---

  const playQuestionSequence = async (q: Question, index: number) => {
    setIsPreloading(true);
    setVisibleOptions([]);

    // 1. PRECARGA PARALELA
    const promises: Promise<any>[] = [];

    // Escenario
    const scenarioText = q.speechScript || q.scenario;
    promises.push(fetchAudioBuffer(scenarioText, q.audioFileUrl)); // Index 0

    // Opciones
    q.options.forEach(opt => {
      const text = `Opción ${opt.key.toUpperCase()}... ${opt.text}`;
      promises.push(fetchAudioBuffer(text));
    });

    // Pregunta de cierre (si no hay audio custom) Y SOLO SI ES LA PRIMERA PREGUNTA
    let closingIndex = -1;
    if (index === 0 && !q.audioFileUrl && !q.speechScript) {
      const closingText = "¿Con cuál de estas situaciones te sientes más identificado?";
      promises.push(fetchAudioBuffer(closingText));
      closingIndex = promises.length - 1; // Última promesa
    }

    const buffers = await Promise.all(promises);
    setIsPreloading(false);

    // 2. REPRODUCCION SECUENCIAL SIN PAUSAS
    // Escenario
    if (buffers[0]) await playBuffer(buffers[0]);
    else await nativeSpeak(scenarioText);

    // Opciones (Sincronizadas: Muestro -> Sueno)
    for (let i = 0; i < q.options.length; i++) {
      const opt = q.options[i];
      const buff = buffers[i + 1]; // Offset por el escenario

      setVisibleOptions(prev => [...prev, opt.key]); // MOSTRAR AL INSTANTE QUE VA A SONAR

      if (buff) await playBuffer(buff);
      else await nativeSpeak(`Opción ${opt.key}... ${opt.text}`);
    }

    // Cierre (Solo si es la primera pregunta)
    if (closingIndex !== -1 && index === 0) {
      const closingBuff = buffers[closingIndex];
      if (closingBuff) await playBuffer(closingBuff);
      else await nativeSpeak("¿Con cuál de estas situaciones te sientes más identificado?");
    }
  };

  // --- FLUJO DE SESION ---

  const startSession = async () => {
    if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();

    setStep('verification');
    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');

    // Reproducir Intro Precargada (Prioridad: MP3 Custom > IA > Native)
    // introBufferRef ya fue cargado usando fetchAudioBuffer que respeta esa prioridad.
    if (introBufferRef.current) await playBuffer(introBufferRef.current);
    else await nativeSpeak(introText);

    // Pregunta Nombre
    addMessage(nameQuestion, 'ia');
    if (nameQuestionBufferRef.current) await playBuffer(nameQuestionBufferRef.current);
    else await nativeSpeak(nameQuestion);
  };

  const handleVerification = async (nameInput: string) => {
    const inputClean = nameInput.trim();
    addMessage(nameInput, 'user');

    if (verificationAttempts === 0) {
        // PRIMER INTENTO: Comprobación contra registro
        const nameToMatch = isEditorMode ? "Coordinador" : (currentPatientData.nombre || "");
        const inputLower = inputClean.toLowerCase();
        const expectedLower = nameToMatch.split(' ')[0].toLowerCase();

        if (inputLower.includes(expectedLower) || expectedLower.includes(inputLower) || isEditorMode) {
            // COINCIDE
            proceedToQuestionnaire();
        } else {
            // NO COINCIDE
            const mismatchMsg = `El nombre no coincide con nuestros registros (${currentPatientData.nombre}). Por favor, escribe el nombre completo por el que quieres ser conocido en los informes y pulsa Confirmar.`;
            setVerificationAttempts(1);
            addMessage(mismatchMsg, 'ia');

            // Generar audio al vuelo para el error (caso borde)
            const errorBuff = await fetchAudioBuffer(mismatchMsg);
            if (errorBuff) await playBuffer(errorBuff);
            else await nativeSpeak(mismatchMsg);
        }
    } else {
        // SEGUNDO INTENTO: Aceptamos el nuevo nombre
        setCurrentPatientData({ ...currentPatientData, nombre: inputClean });
        const acceptedMsg = `Entendido, actualizamos tu ficha como "${inputClean}". Comenzamos el cuestionario.`;
        addMessage(acceptedMsg, 'ia');

        const accBuff = await fetchAudioBuffer(acceptedMsg);
        if (accBuff) await playBuffer(accBuff);
        else await nativeSpeak(acceptedMsg);

        setTimeout(proceedToQuestionnaire, 500);
    }
  };

  const proceedToQuestionnaire = async () => {
    stopAudio();
    const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
    addMessage(welcome, 'ia');

    // Play welcome simple
    const b = await fetchAudioBuffer(welcome);
    if (b) await playBuffer(b);
    else await nativeSpeak(welcome);

    setStep('questionnaire');
    loadQuestion(0);
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${currentPatientData.nombre?.split(' ')[0] || 'amigo/a'}, en breve nos volveremos a poner en contacto para ofrecerte una hoja de ruta.`;
      addMessage(goodbye, 'ia');
      const b = await fetchAudioBuffer(goodbye);
      if (b) await playBuffer(b);
      else await nativeSpeak(goodbye);
      return;
    }

    playQuestionSequence(q, index);
  };

  const handleAnswer = (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  // --- UI RENDER ---

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  // --- EDITOR LOGIC (Sin cambios mayores) ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { setEditingQuestion({ ...editingQuestion, audioFileUrl: event.target?.result as string }); };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  if (step === 'loading') {
    return <div className="min-h-screen flex items-center justify-center bg-slate-50"><div className="animate-spin w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full"></div></div>;
  }

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Sin lectura</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>

              {isPreloading && (
                <div className="absolute top-4 right-6 flex items-center gap-2">
                    <div className="w-4 h-4 border-2 border-blue-400 border-t-transparent rounded-full animate-spin"></div>
                    <span className="text-[10px] uppercase font-black opacity-50">Cargando Audio...</span>
                </div>
              )}

              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-12 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <div className="mb-8">
                 <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-3xl mx-auto mb-4 animate-in zoom-in duration-500">
                    <i className="fas fa-check"></i>
                 </div>
                 <h2 className={`text-2xl font-bold mb-2 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>¡Gracias {currentPatientData.nombre?.split(' ')[0]}!</h2>
                 <p className={`font-medium max-w-xs mx-auto text-sm opacity-80 ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Has completado tu primer paso con valentía.</p>
              </div>

              {isGeneratingReport ? (
                <div className="flex flex-col items-center gap-4 py-6">
                   <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                   <p className="text-xs font-black uppercase text-blue-500 animate-pulse">Generando Informe IA...</p>
                </div>
              ) : (
                <div className="px-6 pb-8 animate-in slide-in-from-bottom-4">
                   <p className="text-xs text-slate-400 mb-6">Tus respuestas y la valoración del Radar están listas para ser enviadas a tu coordinador.</p>
                   <Button onClick={sendResultsToCoordinator} className="w-full py-4 text-lg shadow-xl shadow-green-500/20 bg-green-600 hover:bg-green-700">
                     <i className="fas fa-paper-plane mr-2"></i> Enviar Resultados al Profesional
                   </Button>
                   <p className="text-[9px] text-slate-400 mt-4 max-w-[250px] mx-auto">Al pulsar, se abrirá tu aplicación de correo para enviar el informe generado.</p>
                </div>
              )}

              {isEditorMode && <Button onClick={onExitEditor} variant="outline" className="mt-4 mx-6">Salir del Editor</Button>}
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl, 
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder={verificationAttempts === 0 ? "Tu nombre..." : "Nombre correcto..."} className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones de Respuesta</label>
                    {editingQuestion.options.map((opt, idx) => (<div key={opt.key} className="flex gap-3"><span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span><input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} /></div>))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Personalizado</label><input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={handleFileUpload} /><label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10"><i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Cargado (Listo)' : 'Subir Archivo MP3'}</label></div>

                {editingQuestion.id !== 'intro' && (
                  <div className="bg-[#1f2937] p-4 rounded-2xl"><label className="block text-[10px] font-black uppercase text-blue-300 mb-2">Guion Específico IA (Opcional)</label><textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[140px] outline-none focus:border-blue-500 text-white" placeholder="Si se deja vacío, la IA leerá el escenario y las opciones." value={editingQuestion.speechScript || ''} onChange={e => setEditingQuestion({...editingQuestion, speechScript: e.target.value})} /></div>
                )}
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

export interface CoordinatorProfile {
  nombre: string;
  email: string;
}

export interface AuthUser {
  email: string;
  pin: string; // 4 a 6 dígitos
  nombre: string;
  securityQuestion: string;
  securityAnswer: string;
}

export interface PatientData {
  id: string;
  nombre: string;
  edad: string;
  sexo: string;
  observaciones: string;
  telefono: string;
  email: string;
  coordinatorEmail?: string; // Nuevo campo para el retorno de datos
  status: 'pending' | 'completed' | 'waiting';
  answers?: Record<string, string>;
  conversationSummary?: string;
}

export interface Question {
  id: string;
  scenario: string;
  options: {
    key: string;
    text: string;
    audioUrl?: string; // Nuevo: Audio específico para la opción
  }[];
  speechScript?: string;
  audioFileUrl?: string; // Audio específico para el escenario
  isScale?: boolean;
  scaleLabel?: string;
  followUp?: string;
}

export enum Voice {
  MALE = 'male',
  FEMALE = 'female',
  NONE = 'none'
}

export type View = 'COORDINATOR' | 'PATIENT_SESSION' | 'LANDING';

import { GoogleGenAI } from "@google/genai";

const API_KEY = process.env.API_KEY || "";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY });
  }

  // Se han eliminado decodeAudioData, decodeBase64 y generateSpeechBlock
  // para cumplir estrictamente con la eliminación de voces IA.

  async summarizeSession(patient: any, answers: any, transcript: string): Promise<string> {
    try {
      const prompt = `Resume esta sesión de Cuestionario Espejo. Paciente: ${patient.nombre}. Respuestas: ${JSON.stringify(answers)}. Contexto: ${transcript}. Genera valoración de estado mental relevante para el profesional.`;
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text || "";
    } catch (e) {
      return "No se pudo generar el resumen automáticamente.";
    }
  }
}

export const gemini = new GeminiService();

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_INTRO_TEXT = "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras. El resultado de este cuestionario lo recibirás en breve y te permitirá hacer tu primer ejercicio de autorreflexión personal.";

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2 mb-3`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData: initialPatientData, isEditorMode, onExitEditor }) => {
  const [currentPatientData, setCurrentPatientData] = useState(initialPatientData);

  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [introConfig, setIntroConfig] = useState<{text: string, audioUrl?: string}>(() => {
    const saved = localStorage.getItem('radar_intro_config');
    return saved ? JSON.parse(saved) : { text: DEFAULT_INTRO_TEXT };
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(Voice.FEMALE); // Por defecto mujer
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados para informe
  const [clinicalReport, setClinicalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);

  // Lógica de verificación
  const [verificationAttempts, setVerificationAttempts] = useState(0);

  // Referencias para Audio Nativo / Custom
  const currentAudioRef = useRef<HTMLAudioElement | null>(null);

  // Inicialización de voces del navegador
  useEffect(() => {
    const loadVoices = () => {
      window.speechSynthesis.getVoices();
    };
    loadVoices();
    window.speechSynthesis.onvoiceschanged = loadVoices;

    // Cleanup al desmontar
    return () => {
      window.speechSynthesis.cancel();
      if (currentAudioRef.current) {
        currentAudioRef.current.pause();
        currentAudioRef.current = null;
      }
    };
  }, []);

  // Efecto reporte final
  useEffect(() => {
    if (step === 'finish' && !clinicalReport && !isEditorMode) {
      generateClinicalReport();
    }
  }, [step]);

  // Scroll automático
  useEffect(() => {
    if (step === 'verification') {
       window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    } else {
       window.scrollTo({ top: 0, behavior: 'instant' });
    }
  }, [transcript, step]);

  // --- SERVICIOS AUXILIARES ---

  const generateClinicalReport = async () => {
    setIsGeneratingReport(true);
    const context = transcript.map(t => `${t.sender}: ${t.text}`).join('\n');
    const summary = await gemini.summarizeSession(currentPatientData, answers, context);
    setClinicalReport(summary);
    setIsGeneratingReport(false);
  };

  const sendResultsToCoordinator = () => {
    if (!currentPatientData.coordinatorEmail && !isEditorMode) {
      alert("No se ha encontrado el email del coordinador.");
      return;
    }

    const email = currentPatientData.coordinatorEmail || 'cuestionarioespejo@gmail.com';
    const subject = `RESULTADOS: ${currentPatientData.nombre || 'Paciente'} - Cuestionario Espejo`;

    const body = `INFORME DE SESIÓN - CUESTIONARIO ESPEJO
------------------------------------------------
PACIENTE: ${currentPatientData.nombre || 'N/A'}
EDAD: ${currentPatientData.edad || 'N/A'}
FECHA: ${new Date().toLocaleDateString()}
------------------------------------------------

VALORACIÓN IA (GEMINI):
${clinicalReport}

------------------------------------------------
RESPUESTAS CRUDAS:
${Object.entries(answers).map(([qid, ans]) => `P${qid}: ${ans}`).join('\n')}
`;

    window.location.href = `mailto:${email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  };

  // --- MOTOR DE AUDIO (RENOVADO: NATIVO + ARCHIVOS) ---

  const playOrSpeak = async (text: string, customUrl?: string): Promise<void> => {
    // Detener cualquier audio previo
    window.speechSynthesis.cancel();
    if (currentAudioRef.current) {
      currentAudioRef.current.pause();
      currentAudioRef.current = null;
    }

    if (voice === Voice.NONE) {
        // Simular un pequeño delay si no hay voz para dar tiempo a leer
        return new Promise(resolve => setTimeout(resolve, 1500));
    }

    setIsSpeaking(true);

    return new Promise((resolve) => {
      // 1. Prioridad: Audio Personalizado (MP3)
      if (customUrl) {
        const audio = new Audio(customUrl);
        currentAudioRef.current = audio;
        audio.onended = () => {
          setIsSpeaking(false);
          currentAudioRef.current = null;
          resolve();
        };
        audio.onerror = () => {
          // Si falla el audio, fallback a voz nativa
          console.warn("Error reproduciendo audio custom, usando voz nativa");
          speakNative(text, resolve);
        };
        audio.play().catch(() => speakNative(text, resolve));
        return;
      }

      // 2. Fallback: Voz Nativa del Navegador
      speakNative(text, resolve);
    });
  };

  const speakNative = (text: string, onEnd: () => void) => {
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'es-ES';

    const voices = window.speechSynthesis.getVoices().filter(v => v.lang.startsWith('es'));
    // Intentar seleccionar voz basada en género (muy heurístico ya que varía por navegador)
    if (voices.length > 0) {
        if (voice === Voice.MALE) {
            // Intentar buscar una voz masculina o usar la segunda disponible
            const maleVoice = voices.find(v => v.name.toLowerCase().includes('male') || v.name.toLowerCase().includes('hombre')) || voices[1] || voices[0];
            utterance.voice = maleVoice;
            utterance.pitch = 0.9; // Un poco más grave
        } else {
             // Intentar buscar una voz femenina o usar la primera disponible (default suele ser mujer en muchos OS)
             const femaleVoice = voices.find(v => v.name.toLowerCase().includes('female') || v.name.toLowerCase().includes('mujer')) || voices[0];
             utterance.voice = femaleVoice;
             utterance.pitch = 1.1; // Un poco más aguda
        }
    }

    utterance.onend = () => {
      setIsSpeaking(false);
      onEnd();
    };
    utterance.onerror = () => {
      setIsSpeaking(false);
      onEnd();
    };

    window.speechSynthesis.speak(utterance);
  };

  const stopAudio = () => {
    window.speechSynthesis.cancel();
    if (currentAudioRef.current) {
      currentAudioRef.current.pause();
      currentAudioRef.current = null;
    }
    setIsSpeaking(false);
  };

  // --- LOGICA DE SECUENCIA DE PREGUNTAS ---

  const playQuestionSequence = async (q: Question, index: number) => {
    setVisibleOptions([]);

    // 1. Escenario
    const scenarioText = q.speechScript || q.scenario;
    await playOrSpeak(scenarioText, q.audioFileUrl);

    // 2. Opciones una a una (Visualización coordinada con Audio)
    for (const opt of q.options) {
      setVisibleOptions(prev => [...prev, opt.key]); // Aparece en pantalla
      const textToRead = `Opción ${opt.key}... ${opt.text}`;
      // Usar audio específico de la opción si existe, si no, leer
      await playOrSpeak(textToRead, opt.audioUrl);
    }

    // 3. Cierre (Solo primera pregunta)
    if (index === 0) {
      await playOrSpeak("¿Con cuál de estas situaciones te sientes más identificado?");
    }
  };

  // --- FLUJO DE SESION ---

  const startSession = async () => {
    setStep('verification');
    const introText = introConfig.text;
    const nameQuestion = "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.";

    addMessage(introText, 'ia');
    await playOrSpeak(introText, introConfig.audioUrl);

    addMessage(nameQuestion, 'ia');
    await playOrSpeak(nameQuestion);
  };

  const handleVerification = async (nameInput: string) => {
    stopAudio();
    const inputClean = nameInput.trim();
    addMessage(nameInput, 'user');

    if (verificationAttempts === 0) {
        const nameToMatch = isEditorMode ? "Coordinador" : (currentPatientData.nombre || "");
        const inputLower = inputClean.toLowerCase();
        const expectedLower = nameToMatch.split(' ')[0].toLowerCase();

        if (inputLower.includes(expectedLower) || expectedLower.includes(inputLower) || isEditorMode) {
            proceedToQuestionnaire();
        } else {
            const mismatchMsg = `El nombre no coincide con nuestros registros (${currentPatientData.nombre}). Por favor, escribe el nombre completo por el que quieres ser conocido en los informes y pulsa Confirmar.`;
            setVerificationAttempts(1);
            addMessage(mismatchMsg, 'ia');
            await playOrSpeak(mismatchMsg);
        }
    } else {
        setCurrentPatientData({ ...currentPatientData, nombre: inputClean });
        const acceptedMsg = `Entendido, actualizamos tu ficha como "${inputClean}". Comenzamos el cuestionario.`;
        addMessage(acceptedMsg, 'ia');
        await playOrSpeak(acceptedMsg);
        setTimeout(proceedToQuestionnaire, 500);
    }
  };

  const proceedToQuestionnaire = async () => {
    stopAudio();
    const welcome = "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.";
    addMessage(welcome, 'ia');
    await playOrSpeak(welcome);

    setStep('questionnaire');
    loadQuestion(0);
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer poder conversar contigo ${currentPatientData.nombre?.split(' ')[0] || 'amigo/a'}, en breve nos volveremos a poner en contacto para ofrecerte una hoja de ruta.`;
      addMessage(goodbye, 'ia');
      await playOrSpeak(goodbye);
      return;
    }

    playQuestionSequence(q, index);
  };

  const handleAnswer = (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  // --- EDITOR LOGIC (ACTUALIZADO PARA OPCIONES) ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, target: 'scenario' | 'option', optionIndex?: number) => {
    if (!editingQuestion) return;
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { 
        const result = event.target?.result as string;
        if (target === 'scenario') {
            setEditingQuestion({ ...editingQuestion, audioFileUrl: result }); 
        } else if (target === 'option' && typeof optionIndex === 'number') {
            const newOptions = [...editingQuestion.options];
            newOptions[optionIndex].audioUrl = result;
            setEditingQuestion({ ...editingQuestion, options: newOptions });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const saveEditorChanges = () => {
    if (!editingQuestion) return;
    if (editingQuestion.id === 'intro') {
      const newIntroConfig = {
        text: editingQuestion.scenario,
        audioUrl: editingQuestion.audioFileUrl
      };
      setIntroConfig(newIntroConfig);
      localStorage.setItem('radar_intro_config', JSON.stringify(newIntroConfig));
    } else {
      const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
      setQuestions(updated);
      localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    }
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode 
    ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" 
    : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />
          <div className={`flex rounded-2xl p-1 border ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
            <button onClick={() => setVoice(Voice.FEMALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
            <button onClick={() => setVoice(Voice.MALE)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
            <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Silencio</button>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">

          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>

              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-12 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
              <div className="mb-8">
                 <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-3xl mx-auto mb-4 animate-in zoom-in duration-500">
                    <i className="fas fa-check"></i>
                 </div>
                 <h2 className={`text-2xl font-bold mb-2 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>¡Gracias {currentPatientData.nombre?.split(' ')[0]}!</h2>
                 <p className={`font-medium max-w-xs mx-auto text-sm opacity-80 ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>Has completado tu primer paso con valentía.</p>
              </div>

              {isGeneratingReport ? (
                <div className="flex flex-col items-center gap-4 py-6">
                   <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                   <p className="text-xs font-black uppercase text-blue-500 animate-pulse">Generando Informe...</p>
                </div>
              ) : (
                <div className="px-6 pb-8 animate-in slide-in-from-bottom-4">
                   <p className="text-xs text-slate-400 mb-6">Tus respuestas y la valoración del Radar están listas para ser enviadas a tu coordinador.</p>
                   <Button onClick={sendResultsToCoordinator} className="w-full py-4 text-lg shadow-xl shadow-green-500/20 bg-green-600 hover:bg-green-700">
                     <i className="fas fa-paper-plane mr-2"></i> Enviar Resultados al Profesional
                   </Button>
                </div>
              )}

              {isEditorMode && <Button onClick={onExitEditor} variant="outline" className="mt-4 mx-6">Salir del Editor</Button>}
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">
                Empezar Cuestionario
              </Button>
              {isEditorMode && (
                  <button 
                    onClick={() => setEditingQuestion({ 
                      id: 'intro', 
                      scenario: introConfig.text, 
                      options: [], 
                      audioFileUrl: introConfig.audioUrl, 
                      speechScript: "" 
                    })} 
                    className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"
                  >
                    <i className="fas fa-edit"></i> Editar Mensaje de Bienvenida
                  </button>
                )}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'
                  }`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder={verificationAttempts === 0 ? "Tu nombre..." : "Nombre correcto..."} className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500 placeholder:text-white/30' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600 placeholder:text-blue-800/40'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}>
                <i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i>
              </button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4">
                <i className="fas fa-sliders-h text-blue-500"></i> 
                {editingQuestion.id === 'intro' ? 'Editor de Bienvenida' : 'Editor de Pregunta'}
              </h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">
                    {editingQuestion.id === 'intro' ? 'Texto de Bienvenida' : 'Escenario de la Pregunta'}
                  </label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[150px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                </div>

                {editingQuestion.id !== 'intro' && (
                  <div className="space-y-3">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Opciones y Audios</label>
                    {editingQuestion.options.map((opt, idx) => (
                        <div key={opt.key} className="flex flex-col gap-2 bg-white/5 p-3 rounded-xl border border-white/5">
                            <div className="flex gap-3">
                                <span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span>
                                <input className="flex-1 border-2 border-white/10 bg-white/5 px-4 py-2 rounded-xl text-sm font-black outline-none focus:border-blue-500 text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} />
                            </div>
                            <div className="flex items-center gap-3 pl-11">
                                <label className="cursor-pointer bg-indigo-600/20 hover:bg-indigo-600/40 text-indigo-300 text-[10px] px-3 py-1 rounded-lg transition-colors border border-indigo-500/30 flex items-center gap-2">
                                    <i className="fas fa-microphone"></i> {opt.audioUrl ? 'Audio Grabado (Cambiar)' : 'Subir Audio Opción'}
                                    <input type="file" accept="audio/*" className="hidden" onChange={(e) => handleFileUpload(e, 'option', idx)} />
                                </label>
                                {opt.audioUrl && <span className="text-[9px] text-green-400 font-bold"><i className="fas fa-check"></i> Listo</span>}
                            </div>
                        </div>
                    ))}
                  </div>
                )}
              </div>
              <div className="space-y-6 bg-white/5 p-6 rounded-[2.5rem] border border-white/10">
                <div className="bg-[#1f2937] p-4 rounded-2xl">
                    <label className="block text-[10px] font-black uppercase text-indigo-300 mb-2">Audio MP3 Escenario / Pregunta</label>
                    <input type="file" accept="audio/*" className="hidden" id="audio-upload" onChange={(e) => handleFileUpload(e, 'scenario')} />
                    <label htmlFor="audio-upload" className="flex items-center justify-center gap-2 w-full py-4 border-2 border-dashed border-indigo-500/50 rounded-xl bg-indigo-500/5 cursor-pointer text-xs font-black text-white uppercase transition-colors hover:bg-indigo-500/10">
                        <i className="fas fa-cloud-upload-alt text-xl"></i> {editingQuestion.audioFileUrl ? 'Archivo Pregunta Cargado (Listo)' : 'Subir Archivo Pregunta'}
                    </label>
                </div>
                <div className="p-4 rounded-2xl bg-blue-900/20 border border-blue-500/10">
                    <p className="text-[10px] text-blue-300 leading-relaxed">
                        <i className="fas fa-info-circle mr-1"></i> 
                        <strong>Nota Importante:</strong> Los audios se guardan en el navegador. Si subes archivos para la pregunta y para cada opción, la web coordinará automáticamente: primero sonará la pregunta, luego aparecerá la opción A y sonará su audio, y así sucesivamente.
                    </p>
                </div>
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveEditorChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

export interface CoordinatorProfile {
  nombre: string;
  email: string;
}

export interface AuthUser {
  email: string;
  pin: string; // 4 a 6 dígitos
  nombre: string;
  securityQuestion: string;
  securityAnswer: string;
}

export interface PatientData {
  id: string;
  nombre: string;
  edad: string;
  sexo: string;
  observaciones: string;
  telefono: string;
  email: string;
  coordinatorEmail?: string; 
  status: 'pending' | 'completed' | 'waiting';
  answers?: Record<string, string>;
  conversationSummary?: string;
}

export interface DualAudio {
  male?: string;
  female?: string;
}

export interface Question {
  id: string;
  scenario: string;
  options: {
    key: string;
    text: string;
    audio?: DualAudio; // Audio específico por género
  }[];
  speechScript?: string;
  audio?: DualAudio; // Audio específico por género para el escenario
  isScale?: boolean;
  scaleLabel?: string;
  followUp?: string;
}

// Configuración global de textos y flujos
export interface GlobalConfig {
  welcomeText: string;
  welcomeAudio: DualAudio;
  nameQuestionText: string;
  nameQuestionAudio: DualAudio;
  startText: string;
  startAudio: DualAudio;
  defaultVoiceMode: Voice;
}

export enum Voice {
  MALE = 'male',
  FEMALE = 'female',
  NONE = 'none'
}

export type View = 'COORDINATOR' | 'PATIENT_SESSION' | 'LANDING';

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question, GlobalConfig, DualAudio } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_CONFIG: GlobalConfig = {
  welcomeText: "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras.",
  welcomeAudio: {},
  nameQuestionText: "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.",
  nameQuestionAudio: {},
  startText: "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.",
  startAudio: {},
  defaultVoiceMode: Voice.FEMALE
};

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2 mb-3`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData: initialPatientData, isEditorMode, onExitEditor }) => {
  const [currentPatientData, setCurrentPatientData] = useState(initialPatientData);

  // Carga de Configuración Global y Preguntas
  const [globalConfig, setGlobalConfig] = useState<GlobalConfig>(() => {
    const saved = localStorage.getItem('radar_global_config');
    return saved ? JSON.parse(saved) : DEFAULT_CONFIG;
  });

  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [voice, setVoice] = useState<Voice>(globalConfig.defaultVoiceMode);
  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados para informe
  const [clinicalReport, setClinicalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');

  // Editor
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isEditingGlobal, setIsEditingGlobal] = useState(false);

  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);
  const [verificationAttempts, setVerificationAttempts] = useState(0);

  // Referencias para Audio
  const currentAudioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    const loadVoices = () => { window.speechSynthesis.getVoices(); };
    loadVoices();
    window.speechSynthesis.onvoiceschanged = loadVoices;

    return () => {
      stopAudio();
    };
  }, []);

  useEffect(() => {
    if (step === 'finish' && !clinicalReport && !isEditorMode) {
      generateClinicalReport();
    }
  }, [step]);

  useEffect(() => {
    window.scrollTo({ top: step === 'verification' ? document.body.scrollHeight : 0, behavior: 'smooth' });
  }, [transcript, step]);

  // --- SERVICIOS AUXILIARES ---

  const generateClinicalReport = async () => {
    setIsGeneratingReport(true);
    const context = transcript.map(t => `${t.sender}: ${t.text}`).join('\n');
    const summary = await gemini.summarizeSession(currentPatientData, answers, context);
    setClinicalReport(summary);
    setIsGeneratingReport(false);
  };

  const sendResultsToCoordinator = () => {
    if (!currentPatientData.coordinatorEmail && !isEditorMode) {
      alert("No se ha encontrado el email del coordinador.");
      return;
    }
    const email = currentPatientData.coordinatorEmail || 'cuestionarioespejo@gmail.com';
    const subject = `RESULTADOS: ${currentPatientData.nombre || 'Paciente'} - Cuestionario Espejo`;
    const body = `INFORME DE SESIÓN - CUESTIONARIO ESPEJO\nPACIENTE: ${currentPatientData.nombre || 'N/A'}\nEDAD: ${currentPatientData.edad || 'N/A'}\n\nVALORACIÓN IA:\n${clinicalReport}\n\nRESPUESTAS:\n${Object.entries(answers).map(([qid, ans]) => `P${qid}: ${ans}`).join('\n')}`;
    window.location.href = `mailto:${email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  };

  // --- MOTOR DE AUDIO (LOGICA MEJORADA) ---

  const playOrSpeak = async (text: string, audioData?: DualAudio): Promise<void> => {
    stopAudio();

    if (voice === Voice.NONE) {
        return new Promise(resolve => setTimeout(resolve, 1500));
    }

    setIsSpeaking(true);

    return new Promise((resolve) => {
      // 1. Audio Personalizado según género
      const customUrl = voice === Voice.MALE ? audioData?.male : audioData?.female;

      if (customUrl) {
        const audio = new Audio(customUrl);
        currentAudioRef.current = audio;
        audio.onended = () => {
          setIsSpeaking(false);
          currentAudioRef.current = null;
          resolve();
        };
        audio.onerror = () => {
          console.warn("Error reproduciendo audio custom, usando voz nativa");
          speakNative(text, resolve);
        };
        audio.play().catch(() => speakNative(text, resolve));
        return;
      }

      // 2. Voz Nativa
      speakNative(text, resolve);
    });
  };

  const speakNative = (text: string, onEnd: () => void) => {
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'es-ES';

    const voices = window.speechSynthesis.getVoices();
    // Filtro amplio para encontrar voces en español
    const esVoices = voices.filter(v => v.lang.includes('es') || v.lang.includes('ES'));

    if (esVoices.length > 0) {
        if (voice === Voice.MALE) {
            // Prioridad solicitada: Google Español, Paulina, Elena (Aunque sean nombres femeninos, el usuario pidió usarlos en la pestaña Hombre)
            // Intentamos encontrar voces de alta calidad primero
            const preferred = esVoices.find(v => 
              v.name.includes('Google español') || 
              v.name.includes('Microsoft Elena') || 
              v.name.includes('Paulina') ||
              v.name.includes('Mexico')
            );

            // Si no encuentra las específicas, busca una marcada como "Male" o usa la primera disponible
            const maleGeneric = esVoices.find(v => v.name.toLowerCase().includes('male') || v.name.toLowerCase().includes('hombre'));

            utterance.voice = preferred || maleGeneric || esVoices[0];
            // Ajustamos pitch para simular tono si es necesario, aunque si seleccionó "Elena" sonará a Elena.
            if (!preferred) utterance.pitch = 0.9; 
        } else {
             // Pestaña Mujer: Prioridad a voces femeninas estándar
             const femaleVoice = esVoices.find(v => v.name.toLowerCase().includes('female') || v.name.toLowerCase().includes('mujer')) || esVoices[0];
             utterance.voice = femaleVoice;
             utterance.pitch = 1.1; 
        }
    }

    utterance.onend = () => { setIsSpeaking(false); onEnd(); };
    utterance.onerror = () => { setIsSpeaking(false); onEnd(); };
    window.speechSynthesis.speak(utterance);
  };

  const stopAudio = () => {
    window.speechSynthesis.cancel();
    if (currentAudioRef.current) {
      currentAudioRef.current.pause();
      currentAudioRef.current = null;
    }
    setIsSpeaking(false);
  };

  // --- NAVEGACION ---

  const handleExit = () => {
    if (confirm("¿Estás seguro de que deseas abandonar el cuestionario? Tu progreso se perderá.")) {
      stopAudio();
      window.location.reload();
    }
  };

  const handleBack = () => {
    stopAudio();
    if (currentQuestionIndex > 0) {
      const prevIdx = currentQuestionIndex - 1;
      // Eliminar respuesta de la pregunta actual para evitar inconsistencias
      const prevQId = questions[prevIdx].id;
      // No borramos la respuesta anterior, solo volvemos para editarla
      setCurrentQuestionIndex(prevIdx);
      setTranscript(t => t.slice(0, -1)); // Eliminar el último mensaje de "Me identifico..." visualmente
      loadQuestion(prevIdx);
    }
  };

  // --- LOGICA DE SECUENCIA DE PREGUNTAS ---

  const playQuestionSequence = async (q: Question, index: number) => {
    setVisibleOptions([]);

    // 1. Escenario
    const scenarioText = q.speechScript || q.scenario;
    await playOrSpeak(scenarioText, q.audio);

    // 2. Opciones una a una
    for (const opt of q.options) {
      setVisibleOptions(prev => [...prev, opt.key]); 
      const textToRead = `Opción ${opt.key}... ${opt.text}`;
      await playOrSpeak(textToRead, opt.audio);
    }

    // 3. Cierre (Solo primera pregunta)
    if (index === 0) {
      await playOrSpeak("¿Con cuál de estas situaciones te sientes más identificado?");
    }
  };

  // --- FLUJO DE SESION ---

  const startSession = async () => {
    setStep('verification');
    addMessage(globalConfig.welcomeText, 'ia');
    await playOrSpeak(globalConfig.welcomeText, globalConfig.welcomeAudio);

    addMessage(globalConfig.nameQuestionText, 'ia');
    await playOrSpeak(globalConfig.nameQuestionText, globalConfig.nameQuestionAudio);
  };

  const handleVerification = async (nameInput: string) => {
    stopAudio();
    const inputClean = nameInput.trim();
    addMessage(nameInput, 'user');

    if (verificationAttempts === 0) {
        const nameToMatch = isEditorMode ? "Coordinador" : (currentPatientData.nombre || "");
        const inputLower = inputClean.toLowerCase();
        const expectedLower = nameToMatch.split(' ')[0].toLowerCase();

        if (inputLower.includes(expectedLower) || expectedLower.includes(inputLower) || isEditorMode) {
            proceedToQuestionnaire();
        } else {
            const mismatchMsg = `El nombre no coincide con nuestros registros (${currentPatientData.nombre}). Por favor, escribe el nombre completo.`;
            setVerificationAttempts(1);
            addMessage(mismatchMsg, 'ia');
            await playOrSpeak(mismatchMsg);
        }
    } else {
        setCurrentPatientData({ ...currentPatientData, nombre: inputClean });
        const acceptedMsg = `Entendido, actualizamos tu ficha como "${inputClean}".`;
        addMessage(acceptedMsg, 'ia');
        await playOrSpeak(acceptedMsg);
        setTimeout(proceedToQuestionnaire, 500);
    }
  };

  const proceedToQuestionnaire = async () => {
    stopAudio();
    addMessage(globalConfig.startText, 'ia');
    await playOrSpeak(globalConfig.startText, globalConfig.startAudio);

    setStep('questionnaire');
    loadQuestion(0);
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer, ${currentPatientData.nombre?.split(' ')[0] || 'amigo/a'}.`;
      addMessage(goodbye, 'ia');
      await playOrSpeak(goodbye);
      return;
    }

    playQuestionSequence(q, index);
  };

  const handleAnswer = (key: string) => {
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  // --- EDITOR LOGIC ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: string, subIndex?: number, gender: 'male' | 'female' = 'female') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { 
        const result = event.target?.result as string;

        if (isEditingGlobal) {
           const newConfig = { ...globalConfig };
           if (field === 'welcome') newConfig.welcomeAudio = { ...newConfig.welcomeAudio, [gender]: result };
           if (field === 'name') newConfig.nameQuestionAudio = { ...newConfig.nameQuestionAudio, [gender]: result };
           if (field === 'start') newConfig.startAudio = { ...newConfig.startAudio, [gender]: result };
           setGlobalConfig(newConfig);
        } else if (editingQuestion) {
           if (field === 'scenario') {
              const audio = editingQuestion.audio || {};
              setEditingQuestion({ ...editingQuestion, audio: { ...audio, [gender]: result } }); 
           } else if (field === 'option' && typeof subIndex === 'number') {
              const newOptions = [...editingQuestion.options];
              const optAudio = newOptions[subIndex].audio || {};
              newOptions[subIndex].audio = { ...optAudio, [gender]: result };
              setEditingQuestion({ ...editingQuestion, options: newOptions });
           }
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const saveGlobalChanges = () => {
    localStorage.setItem('radar_global_config', JSON.stringify(globalConfig));
    setIsEditingGlobal(false);
  };

  const saveQuestionChanges = () => {
    if (!editingQuestion) return;
    const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
    setQuestions(updated);
    localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  // --- RENDER HELPERS ---
  const AudioUploadButton = ({ label, hasAudio, onChange }: { label: string, hasAudio: boolean, onChange: (e: any) => void }) => (
    <label className={`cursor-pointer px-3 py-2 rounded-lg text-[10px] font-bold uppercase transition-all flex items-center gap-2 border ${hasAudio ? 'bg-green-500/10 text-green-400 border-green-500/30' : 'bg-white/5 text-slate-400 border-white/10 hover:bg-white/10'}`}>
       <i className={`fas ${hasAudio ? 'fa-check' : 'fa-microphone'}`}></i> {label}
       <input type="file" accept="audio/*" className="hidden" onChange={onChange} />
    </label>
  );

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex justify-between items-center gap-3">
          <Logo size="sm" isDark={isDarkMode} />

          <div className="flex items-center gap-2">
             {/* Navegación y Salida */}
             {step === 'questionnaire' && (
                <>
                  <button onClick={handleBack} disabled={currentQuestionIndex === 0} className="w-8 h-8 rounded-full bg-slate-200/50 text-slate-600 flex items-center justify-center hover:bg-slate-300 disabled:opacity-30 transition-all">
                    <i className="fas fa-chevron-left"></i>
                  </button>
                  <button onClick={handleExit} className="w-8 h-8 rounded-full bg-red-100 text-red-500 flex items-center justify-center hover:bg-red-200 transition-all ml-2">
                    <i className="fas fa-door-open"></i>
                  </button>
                </>
             )}

             <div className={`flex rounded-2xl p-1 border ml-4 ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
                <button onClick={() => setVoice(Voice.FEMALE)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
                <button onClick={() => setVoice(Voice.MALE)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
                <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Silencio</button>
             </div>
          </div>
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">
          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>
              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-12 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
               <div className="mb-8"><div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-3xl mx-auto mb-4 animate-in zoom-in duration-500"><i className="fas fa-check"></i></div><h2 className={`text-2xl font-bold mb-2 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>¡Gracias {currentPatientData.nombre?.split(' ')[0]}!</h2></div>
               {isGeneratingReport ? <div className="flex flex-col items-center gap-4 py-6"><div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div><p className="text-xs font-black uppercase text-blue-500 animate-pulse">Generando Informe...</p></div> : <div className="px-6 pb-8 animate-in slide-in-from-bottom-4"><p className="text-xs text-slate-400 mb-6">Tus respuestas y la valoración del Radar están listas para ser enviadas a tu coordinador.</p><Button onClick={sendResultsToCoordinator} className="w-full py-4 text-lg shadow-xl shadow-green-500/20 bg-green-600 hover:bg-green-700"><i className="fas fa-paper-plane mr-2"></i> Enviar Resultados al Profesional</Button></div>}
               {isEditorMode && <Button onClick={onExitEditor} variant="outline" className="mt-4 mx-6">Salir del Editor</Button>}
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">Empezar Cuestionario</Button>
              {isEditorMode && <button onClick={() => setIsEditingGlobal(true)} className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"><i className="fas fa-cog"></i> Configurar Mensajes y Voces</button>}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button key={opt.key} onClick={() => handleAnswer(opt.key)} className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${isDarkMode ? 'bg-white/10 border-white/20 hover:border-blue-500 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:border-blue-600 hover:bg-blue-50'}`}>
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Escribe aquí..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}><i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i></button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {/* EDITOR GLOBAL (INTRO, NOMBRE, INICIO) */}
      {isEditingGlobal && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
           <Card className="w-full max-w-4xl p-8 bg-[#111827] border-white/20 text-white overflow-y-auto max-h-[90vh] rounded-[3rem]">
              <h3 className="text-2xl font-bold font-friendly mb-6 flex items-center gap-3"><i className="fas fa-cog text-blue-500"></i> Configuración Global y Textos</h3>

              <div className="space-y-8">
                 <div className="bg-white/5 p-6 rounded-3xl border border-white/10">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-4">Voz por Defecto al Iniciar</label>
                    <div className="flex gap-4">
                       {[Voice.FEMALE, Voice.MALE, Voice.NONE].map(v => (
                         <button key={v} onClick={() => setGlobalConfig({...globalConfig, defaultVoiceMode: v})} className={`px-4 py-2 rounded-xl text-xs font-bold uppercase ${globalConfig.defaultVoiceMode === v ? 'bg-blue-600 text-white' : 'bg-white/10 text-slate-400'}`}>{v === 'none' ? 'Silencio' : v === 'male' ? 'Hombre' : 'Mujer'}</button>
                       ))}
                    </div>
                 </div>

                 {[{id: 'welcome', label: '1. Mensaje de Bienvenida (Intro)'}, {id: 'name', label: '2. Pregunta por el Nombre'}, {id: 'start', label: '3. Mensaje Inicio Cuestionario'}].map((section) => (
                    <div key={section.id} className="space-y-4 border-t border-white/10 pt-4">
                       <label className="block text-sm font-bold text-indigo-300">{section.label}</label>
                       <textarea className="w-full bg-white/5 border-2 border-white/10 rounded-xl p-3 text-sm font-medium outline-none focus:border-blue-500" value={(globalConfig as any)[`${section.id}Text`]} onChange={e => setGlobalConfig({...globalConfig, [`${section.id}Text`]: e.target.value})} />
                       <div className="flex gap-4">
                          <AudioUploadButton label="Audio Mujer" hasAudio={!!(globalConfig as any)[`${section.id}Audio`]?.female} onChange={(e) => handleFileUpload(e, section.id, undefined, 'female')} />
                          <AudioUploadButton label="Audio Hombre" hasAudio={!!(globalConfig as any)[`${section.id}Audio`]?.male} onChange={(e) => handleFileUpload(e, section.id, undefined, 'male')} />
                       </div>
                    </div>
                 ))}
              </div>
              <div className="flex gap-4 mt-8 pt-6 border-t border-white/10">
                 <Button onClick={saveGlobalChanges} className="flex-1">Guardar Configuración</Button>
                 <Button variant="outline" onClick={() => setIsEditingGlobal(false)} className="flex-1 border-white/20 text-white">Cancelar</Button>
              </div>
           </Card>
        </div>
      )}

      {/* EDITOR DE PREGUNTAS (AUDIO DOBLE) */}
      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4"><i className="fas fa-edit text-blue-500"></i> Editar Pregunta</h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Escenario</label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[120px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                  <div className="flex gap-4 mt-3">
                     <AudioUploadButton label="Audio Escenario (Mujer)" hasAudio={!!editingQuestion.audio?.female} onChange={(e) => handleFileUpload(e, 'scenario', undefined, 'female')} />
                     <AudioUploadButton label="Audio Escenario (Hombre)" hasAudio={!!editingQuestion.audio?.male} onChange={(e) => handleFileUpload(e, 'scenario', undefined, 'male')} />
                  </div>
                </div>

                <div className="space-y-4">
                    <label className="block text-[10px] font-black uppercase text-blue-400">Opciones</label>
                    {editingQuestion.options.map((opt, idx) => (
                        <div key={opt.key} className="bg-white/5 p-4 rounded-xl border border-white/5">
                            <div className="flex gap-3 mb-3">
                                <span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span>
                                <input className="flex-1 border-2 border-white/10 bg-transparent px-3 py-1 rounded-lg text-sm text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} />
                            </div>
                            <div className="flex gap-3 pl-11">
                                <AudioUploadButton label="Audio Opción (M)" hasAudio={!!opt.audio?.female} onChange={(e) => handleFileUpload(e, 'option', idx, 'female')} />
                                <AudioUploadButton label="Audio Opción (H)" hasAudio={!!opt.audio?.male} onChange={(e) => handleFileUpload(e, 'option', idx, 'male')} />
                            </div>
                        </div>
                    ))}
                </div>
              </div>
              <div className="bg-blue-900/10 p-6 rounded-[2.5rem] border border-blue-500/20 h-fit">
                <p className="text-xs text-blue-200 leading-relaxed font-medium"><i className="fas fa-info-circle mr-2"></i><strong>Sistema Dual:</strong> Ahora puedes subir un audio específico para la voz de MUJER y otro para la de HOMBRE. El sistema reproducirá automáticamente el que corresponda según la selección del usuario en la barra superior.</p>
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveQuestionChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question, GlobalConfig, DualAudio } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_CONFIG: GlobalConfig = {
  welcomeText: "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras.",
  welcomeAudio: {},
  nameQuestionText: "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.",
  nameQuestionAudio: {},
  startText: "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.",
  startAudio: {},
  defaultVoiceMode: Voice.FEMALE
};

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2 mb-3`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData: initialPatientData, isEditorMode, onExitEditor }) => {
  const [currentPatientData, setCurrentPatientData] = useState(initialPatientData);

  // Carga de Configuración Global y Preguntas
  const [globalConfig, setGlobalConfig] = useState<GlobalConfig>(() => {
    const saved = localStorage.getItem('radar_global_config');
    return saved ? JSON.parse(saved) : DEFAULT_CONFIG;
  });

  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);

  // Inicializar voz directamente desde config
  const [voice, setVoice] = useState<Voice>(globalConfig.defaultVoiceMode);

  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados para informe
  const [clinicalReport, setClinicalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');

  // Bloqueo de interacción
  const [isInteractionLocked, setIsInteractionLocked] = useState(false);

  // Editor
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isEditingGlobal, setIsEditingGlobal] = useState(false);

  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);
  const [verificationAttempts, setVerificationAttempts] = useState(0);

  // Referencias para Audio
  const currentAudioRef = useRef<HTMLAudioElement | null>(null);

  // Efecto CRÍTICO: Sincronizar voz si cambia la configuración global (por ejemplo, al editar)
  useEffect(() => {
    setVoice(globalConfig.defaultVoiceMode);
  }, [globalConfig.defaultVoiceMode]);

  useEffect(() => {
    const loadVoices = () => { window.speechSynthesis.getVoices(); };
    loadVoices();
    window.speechSynthesis.onvoiceschanged = loadVoices;

    return () => {
      stopAudio();
    };
  }, []);

  useEffect(() => {
    if (step === 'finish' && !clinicalReport && !isEditorMode) {
      generateClinicalReport();
    }
  }, [step]);

  useEffect(() => {
    window.scrollTo({ top: step === 'verification' ? document.body.scrollHeight : 0, behavior: 'smooth' });
  }, [transcript, step]);

  // --- SERVICIOS AUXILIARES ---

  const generateClinicalReport = async () => {
    setIsGeneratingReport(true);
    const context = transcript.map(t => `${t.sender}: ${t.text}`).join('\n');
    const summary = await gemini.summarizeSession(currentPatientData, answers, context);
    setClinicalReport(summary);
    setIsGeneratingReport(false);
  };

  const sendResultsToCoordinator = () => {
    if (!currentPatientData.coordinatorEmail && !isEditorMode) {
      alert("No se ha encontrado el email del coordinador.");
      return;
    }
    const email = currentPatientData.coordinatorEmail || 'cuestionarioespejo@gmail.com';
    const subject = `RESULTADOS: ${currentPatientData.nombre || 'Paciente'} - Cuestionario Espejo`;
    const body = `INFORME DE SESIÓN - CUESTIONARIO ESPEJO\nPACIENTE: ${currentPatientData.nombre || 'N/A'}\nEDAD: ${currentPatientData.edad || 'N/A'}\n\nVALORACIÓN IA:\n${clinicalReport}\n\nRESPUESTAS:\n${Object.entries(answers).map(([qid, ans]) => `P${qid}: ${ans}`).join('\n')}`;
    window.location.href = `mailto:${email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  };

  // --- MOTOR DE AUDIO ---

  const playOrSpeak = async (text: string, audioData?: DualAudio): Promise<void> => {
    stopAudio();

    if (voice === Voice.NONE) {
        return new Promise(resolve => setTimeout(resolve, 1500));
    }

    setIsSpeaking(true);

    return new Promise((resolve) => {
      // 1. Audio Personalizado según género
      const customUrl = voice === Voice.MALE ? audioData?.male : audioData?.female;

      if (customUrl) {
        const audio = new Audio(customUrl);
        currentAudioRef.current = audio;
        audio.onended = () => {
          setIsSpeaking(false);
          currentAudioRef.current = null;
          resolve();
        };
        audio.onerror = () => {
          console.warn("Error reproduciendo audio custom, usando voz nativa");
          speakNative(text, resolve);
        };
        audio.play().catch(() => speakNative(text, resolve));
        return;
      }

      // 2. Voz Nativa
      speakNative(text, resolve);
    });
  };

  const speakNative = (text: string, onEnd: () => void) => {
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'es-ES';

    const voices = window.speechSynthesis.getVoices();
    const esVoices = voices.filter(v => v.lang.includes('es') || v.lang.includes('ES'));

    if (esVoices.length > 0) {
        if (voice === Voice.MALE) {
            const preferred = esVoices.find(v => 
              v.name.includes('Google español') || 
              v.name.includes('Microsoft Elena') || 
              v.name.includes('Paulina') ||
              v.name.includes('Mexico')
            );
            const maleGeneric = esVoices.find(v => v.name.toLowerCase().includes('male') || v.name.toLowerCase().includes('hombre'));

            utterance.voice = preferred || maleGeneric || esVoices[0];
            if (!preferred) utterance.pitch = 0.9; 
        } else {
             const femaleVoice = esVoices.find(v => v.name.toLowerCase().includes('female') || v.name.toLowerCase().includes('mujer')) || esVoices[0];
             utterance.voice = femaleVoice;
             utterance.pitch = 1.1; 
        }
    }

    utterance.onend = () => { setIsSpeaking(false); onEnd(); };
    utterance.onerror = () => { setIsSpeaking(false); onEnd(); };
    window.speechSynthesis.speak(utterance);
  };

  const stopAudio = () => {
    window.speechSynthesis.cancel();
    if (currentAudioRef.current) {
      currentAudioRef.current.pause();
      currentAudioRef.current = null;
    }
    setIsSpeaking(false);
  };

  // --- NAVEGACION ---

  const handleExit = () => {
    if (confirm("¿Estás seguro de que deseas abandonar el cuestionario? Tu progreso se perderá.")) {
      stopAudio();
      window.location.reload();
    }
  };

  const handleBack = () => {
    stopAudio();
    if (currentQuestionIndex > 0) {
      const prevIdx = currentQuestionIndex - 1;
      setCurrentQuestionIndex(prevIdx);
      setTranscript(t => t.slice(0, -1)); // Eliminar visualmente la última respuesta
      loadQuestion(prevIdx);
    }
  };

  // --- LOGICA DE SECUENCIA DE PREGUNTAS (CON BLOQUEO) ---

  const playQuestionSequence = async (q: Question, index: number) => {
    setIsInteractionLocked(true); // BLOQUEAR AL INICIO
    setVisibleOptions([]);

    // 1. Escenario
    const scenarioText = q.speechScript || q.scenario;
    await playOrSpeak(scenarioText, q.audio);

    // 2. Opciones una a una
    for (const opt of q.options) {
      setVisibleOptions(prev => [...prev, opt.key]); 
      const textToRead = `Opción ${opt.key}... ${opt.text}`;
      await playOrSpeak(textToRead, opt.audio);
    }

    // 3. Cierre (Solo primera pregunta)
    if (index === 0) {
      await playOrSpeak("¿Con cuál de estas situaciones te sientes más identificado?");
    }

    setIsInteractionLocked(false); // DESBLOQUEAR AL FINAL
  };

  // --- FLUJO DE SESION ---

  const startSession = async () => {
    setStep('verification');
    addMessage(globalConfig.welcomeText, 'ia');
    await playOrSpeak(globalConfig.welcomeText, globalConfig.welcomeAudio);

    addMessage(globalConfig.nameQuestionText, 'ia');
    await playOrSpeak(globalConfig.nameQuestionText, globalConfig.nameQuestionAudio);
  };

  const handleVerification = async (nameInput: string) => {
    stopAudio();
    const inputClean = nameInput.trim();
    addMessage(nameInput, 'user');

    if (verificationAttempts === 0) {
        const nameToMatch = isEditorMode ? "Coordinador" : (currentPatientData.nombre || "");
        const inputLower = inputClean.toLowerCase();
        const expectedLower = nameToMatch.split(' ')[0].toLowerCase();

        if (inputLower.includes(expectedLower) || expectedLower.includes(inputLower) || isEditorMode) {
            proceedToQuestionnaire();
        } else {
            const mismatchMsg = `El nombre no coincide con nuestros registros (${currentPatientData.nombre}). Por favor, escribe el nombre completo.`;
            setVerificationAttempts(1);
            addMessage(mismatchMsg, 'ia');
            await playOrSpeak(mismatchMsg);
        }
    } else {
        setCurrentPatientData({ ...currentPatientData, nombre: inputClean });
        const acceptedMsg = `Entendido, actualizamos tu ficha como "${inputClean}".`;
        addMessage(acceptedMsg, 'ia');
        await playOrSpeak(acceptedMsg);
        setTimeout(proceedToQuestionnaire, 500);
    }
  };

  const proceedToQuestionnaire = async () => {
    stopAudio();
    addMessage(globalConfig.startText, 'ia');
    await playOrSpeak(globalConfig.startText, globalConfig.startAudio);

    setStep('questionnaire');
    loadQuestion(0);
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer, ${currentPatientData.nombre?.split(' ')[0] || 'amigo/a'}.`;
      addMessage(goodbye, 'ia');
      await playOrSpeak(goodbye);
      return;
    }

    playQuestionSequence(q, index);
  };

  const handleAnswer = (key: string) => {
    if (isInteractionLocked) return; // DOBLE SEGURIDAD
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  // --- EDITOR LOGIC ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: string, subIndex?: number, gender: 'male' | 'female' = 'female') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { 
        const result = event.target?.result as string;

        if (isEditingGlobal) {
           const newConfig = { ...globalConfig };
           if (field === 'welcome') newConfig.welcomeAudio = { ...newConfig.welcomeAudio, [gender]: result };
           if (field === 'name') newConfig.nameQuestionAudio = { ...newConfig.nameQuestionAudio, [gender]: result };
           if (field === 'start') newConfig.startAudio = { ...newConfig.startAudio, [gender]: result };
           setGlobalConfig(newConfig);
        } else if (editingQuestion) {
           if (field === 'scenario') {
              const audio = editingQuestion.audio || {};
              setEditingQuestion({ ...editingQuestion, audio: { ...audio, [gender]: result } }); 
           } else if (field === 'option' && typeof subIndex === 'number') {
              const newOptions = [...editingQuestion.options];
              const optAudio = newOptions[subIndex].audio || {};
              newOptions[subIndex].audio = { ...optAudio, [gender]: result };
              setEditingQuestion({ ...editingQuestion, options: newOptions });
           }
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const saveGlobalChanges = () => {
    localStorage.setItem('radar_global_config', JSON.stringify(globalConfig));
    setIsEditingGlobal(false);
  };

  const saveQuestionChanges = () => {
    if (!editingQuestion) return;
    const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
    setQuestions(updated);
    localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  // --- RENDER HELPERS ---
  const AudioUploadButton = ({ label, hasAudio, onChange }: { label: string, hasAudio: boolean, onChange: (e: any) => void }) => (
    <label className={`cursor-pointer px-3 py-2 rounded-lg text-[10px] font-bold uppercase transition-all flex items-center gap-2 border ${hasAudio ? 'bg-green-500/10 text-green-400 border-green-500/30' : 'bg-white/5 text-slate-400 border-white/10 hover:bg-white/10'}`}>
       <i className={`fas ${hasAudio ? 'fa-check' : 'fa-microphone'}`}></i> {label}
       <input type="file" accept="audio/*" className="hidden" onChange={onChange} />
    </label>
  );

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex justify-between items-center gap-3 relative">
          <Logo size="sm" isDark={isDarkMode} />

          <div className="flex items-center gap-2 pr-12"> 
             <div className={`flex rounded-2xl p-1 border ml-4 ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
                <button onClick={() => setVoice(Voice.FEMALE)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
                <button onClick={() => setVoice(Voice.MALE)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
                <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Silencio</button>
             </div>
          </div>

          {/* Botón Salir "X" Elegante en esquina derecha */}
          {step === 'questionnaire' && (
            <button 
              onClick={handleExit} 
              className={`absolute right-0 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-full transition-all group ${isDarkMode ? 'hover:bg-red-900/30 text-slate-400 hover:text-red-400' : 'hover:bg-red-50 text-slate-400 hover:text-red-500'}`}
              title="Abandonar cuestionario"
            >
              <i className="fas fa-times text-lg"></i>
            </button>
          )}
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">
          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 pt-12 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>

              {/* Botón Retroceder dentro de la tarjeta */}
              {currentQuestionIndex > 0 && (
                <button 
                  onClick={handleBack} 
                  disabled={isInteractionLocked}
                  className={`absolute top-6 left-6 w-8 h-8 rounded-full flex items-center justify-center transition-all ${isDarkMode ? 'bg-white/10 text-white hover:bg-white/20' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'} disabled:opacity-30`}
                  title="Pregunta anterior"
                >
                  <i className="fas fa-arrow-left text-sm"></i>
                </button>
              )}

              <span className={`text-[10px] font-black uppercase tracking-[0.4em] mb-4 block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'} ${currentQuestionIndex > 0 ? 'mt-2' : ''}`}>Reflexión del Momento</span>
              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-12 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
               <div className="mb-8"><div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-3xl mx-auto mb-4 animate-in zoom-in duration-500"><i className="fas fa-check"></i></div><h2 className={`text-2xl font-bold mb-2 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>¡Gracias {currentPatientData.nombre?.split(' ')[0]}!</h2></div>
               {isGeneratingReport ? <div className="flex flex-col items-center gap-4 py-6"><div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div><p className="text-xs font-black uppercase text-blue-500 animate-pulse">Generando Informe...</p></div> : <div className="px-6 pb-8 animate-in slide-in-from-bottom-4"><p className="text-xs text-slate-400 mb-6">Tus respuestas y la valoración del Radar están listas para ser enviadas a tu coordinador.</p><Button onClick={sendResultsToCoordinator} className="w-full py-4 text-lg shadow-xl shadow-green-500/20 bg-green-600 hover:bg-green-700"><i className="fas fa-paper-plane mr-2"></i> Enviar Resultados al Profesional</Button></div>}
               {isEditorMode && <Button onClick={onExitEditor} variant="outline" className="mt-4 mx-6">Salir del Editor</Button>}
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">Empezar Cuestionario</Button>
              {isEditorMode && <button onClick={() => setIsEditingGlobal(true)} className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"><i className="fas fa-cog"></i> Configurar Mensajes y Voces</button>}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  disabled={isInteractionLocked}
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isInteractionLocked ? 'opacity-50 cursor-wait' : 'cursor-pointer hover:border-blue-600'
                  } ${isDarkMode ? 'bg-white/10 border-white/20 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:bg-blue-50'}`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Escribe aquí..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}><i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i></button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {/* EDITOR GLOBAL (INTRO, NOMBRE, INICIO) */}
      {isEditingGlobal && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
           <Card className="w-full max-w-4xl p-8 bg-[#111827] border-white/20 text-white overflow-y-auto max-h-[90vh] rounded-[3rem]">
              <h3 className="text-2xl font-bold font-friendly mb-6 flex items-center gap-3"><i className="fas fa-cog text-blue-500"></i> Configuración Global y Textos</h3>

              <div className="space-y-8">
                 <div className="bg-white/5 p-6 rounded-3xl border border-white/10">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-4">Voz por Defecto al Iniciar</label>
                    <div className="flex gap-4">
                       {[Voice.FEMALE, Voice.MALE, Voice.NONE].map(v => (
                         <button key={v} onClick={() => setGlobalConfig({...globalConfig, defaultVoiceMode: v})} className={`px-4 py-2 rounded-xl text-xs font-bold uppercase ${globalConfig.defaultVoiceMode === v ? 'bg-blue-600 text-white' : 'bg-white/10 text-slate-400'}`}>{v === 'none' ? 'Silencio' : v === 'male' ? 'Hombre' : 'Mujer'}</button>
                       ))}
                    </div>
                 </div>

                 {[{id: 'welcome', label: '1. Mensaje de Bienvenida (Intro)'}, {id: 'name', label: '2. Pregunta por el Nombre'}, {id: 'start', label: '3. Mensaje Inicio Cuestionario'}].map((section) => (
                    <div key={section.id} className="space-y-4 border-t border-white/10 pt-4">
                       <label className="block text-sm font-bold text-indigo-300">{section.label}</label>
                       <textarea className="w-full bg-white/5 border-2 border-white/10 rounded-xl p-3 text-sm font-medium outline-none focus:border-blue-500" value={(globalConfig as any)[`${section.id}Text`]} onChange={e => setGlobalConfig({...globalConfig, [`${section.id}Text`]: e.target.value})} />
                       <div className="flex gap-4">
                          <AudioUploadButton label="Audio Mujer" hasAudio={!!(globalConfig as any)[`${section.id}Audio`]?.female} onChange={(e) => handleFileUpload(e, section.id, undefined, 'female')} />
                          <AudioUploadButton label="Audio Hombre" hasAudio={!!(globalConfig as any)[`${section.id}Audio`]?.male} onChange={(e) => handleFileUpload(e, section.id, undefined, 'male')} />
                       </div>
                    </div>
                 ))}
              </div>
              <div className="flex gap-4 mt-8 pt-6 border-t border-white/10">
                 <Button onClick={saveGlobalChanges} className="flex-1">Guardar Configuración</Button>
                 <Button variant="outline" onClick={() => setIsEditingGlobal(false)} className="flex-1 border-white/20 text-white">Cancelar</Button>
              </div>
           </Card>
        </div>
      )}

      {/* EDITOR DE PREGUNTAS (AUDIO DOBLE) */}
      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4"><i className="fas fa-edit text-blue-500"></i> Editar Pregunta</h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Escenario</label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[120px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                  <div className="flex gap-4 mt-3">
                     <AudioUploadButton label="Audio Escenario (Mujer)" hasAudio={!!editingQuestion.audio?.female} onChange={(e) => handleFileUpload(e, 'scenario', undefined, 'female')} />
                     <AudioUploadButton label="Audio Escenario (Hombre)" hasAudio={!!editingQuestion.audio?.male} onChange={(e) => handleFileUpload(e, 'scenario', undefined, 'male')} />
                  </div>
                </div>

                <div className="space-y-4">
                    <label className="block text-[10px] font-black uppercase text-blue-400">Opciones</label>
                    {editingQuestion.options.map((opt, idx) => (
                        <div key={opt.key} className="bg-white/5 p-4 rounded-xl border border-white/5">
                            <div className="flex gap-3 mb-3">
                                <span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span>
                                <input className="flex-1 border-2 border-white/10 bg-transparent px-3 py-1 rounded-lg text-sm text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} />
                            </div>
                            <div className="flex gap-3 pl-11">
                                <AudioUploadButton label="Audio Opción (M)" hasAudio={!!opt.audio?.female} onChange={(e) => handleFileUpload(e, 'option', idx, 'female')} />
                                <AudioUploadButton label="Audio Opción (H)" hasAudio={!!opt.audio?.male} onChange={(e) => handleFileUpload(e, 'option', idx, 'male')} />
                            </div>
                        </div>
                    ))}
                </div>
              </div>
              <div className="bg-blue-900/10 p-6 rounded-[2.5rem] border border-blue-500/20 h-fit">
                <p className="text-xs text-blue-200 leading-relaxed font-medium"><i className="fas fa-info-circle mr-2"></i><strong>Sistema Dual:</strong> Ahora puedes subir un audio específico para la voz de MUJER y otro para la de HOMBRE. El sistema reproducirá automáticamente el que corresponda según la selección del usuario en la barra superior.</p>
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveQuestionChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card, Button, Logo, ProgressBar } from './UI';
import { QUESTIONS as INITIAL_QUESTIONS } from '../constants';
import { gemini } from '../services/gemini';
import { PatientData, Voice, Question, GlobalConfig, DualAudio } from '../types';

interface PatientInterfaceProps {
  patientData: Partial<PatientData>;
  isEditorMode?: boolean;
  onExitEditor?: () => void;
}

const DEFAULT_CONFIG: GlobalConfig = {
  welcomeText: "Hola soy el Radar que ahora te va a guiar a través de situaciones cotidianas que nos ayudarán a conocer mejor tu estado. Tus respuestas deben ser reflexionadas y sinceras.",
  welcomeAudio: {},
  nameQuestionText: "¿Cómo te llamas? Por favor, dime tu nombre para confirmar que eres tú.",
  nameQuestionAudio: {},
  startText: "Bienvenido. Vamos a comenzar este viaje como tu primer acto terapéutico.",
  startAudio: {},
  defaultVoiceMode: Voice.FEMALE
};

const ChatBubble: React.FC<{ msg: { text: string, sender: string }, isDarkMode: boolean }> = ({ msg, isDarkMode }) => (
  <div className={`flex ${msg.sender === 'ia' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2 mb-3`}>
    <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm font-medium leading-relaxed shadow-sm border ${
      msg.sender === 'ia' 
        ? (isDarkMode ? 'bg-white/10 text-blue-200 border-white/10' : 'bg-white text-slate-700 border-slate-100') + ' rounded-tl-none' 
        : (isDarkMode ? 'bg-blue-600 text-white border-blue-500' : 'bg-blue-600 text-white border-blue-600') + ' rounded-tr-none shadow-lg'
    }`}>
      {msg.text}
    </div>
  </div>
);

export const PatientInterface: React.FC<PatientInterfaceProps> = ({ patientData: initialPatientData, isEditorMode, onExitEditor }) => {
  const [currentPatientData, setCurrentPatientData] = useState(initialPatientData);

  // Carga de Configuración Global y Preguntas
  const [globalConfig, setGlobalConfig] = useState<GlobalConfig>(() => {
    const saved = localStorage.getItem('radar_global_config');
    return saved ? JSON.parse(saved) : DEFAULT_CONFIG;
  });

  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('radar_custom_questions');
    return saved ? JSON.parse(saved) : INITIAL_QUESTIONS;
  });

  const [step, setStep] = useState<'intro' | 'verification' | 'questionnaire' | 'finish'>('intro');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);

  // Inicializar voz directamente desde config
  const [voice, setVoice] = useState<Voice>(globalConfig.defaultVoiceMode);

  const [transcript, setTranscript] = useState<{ text: string, sender: 'ia' | 'user' }[]>([]);
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Estados para informe
  const [clinicalReport, setClinicalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  // Estados visuales y de control
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [inputValue, setInputValue] = useState('');

  // Bloqueo de interacción
  const [isInteractionLocked, setIsInteractionLocked] = useState(false);

  // Editor
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [isEditingGlobal, setIsEditingGlobal] = useState(false);

  const [isDarkMode, setIsDarkMode] = useState(false);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);
  const [verificationAttempts, setVerificationAttempts] = useState(0);

  // Referencias para Audio
  const currentAudioRef = useRef<HTMLAudioElement | null>(null);

  // Efecto CRÍTICO: Sincronizar voz si cambia la configuración global (por ejemplo, al editar)
  useEffect(() => {
    setVoice(globalConfig.defaultVoiceMode);
  }, [globalConfig.defaultVoiceMode]);

  useEffect(() => {
    const loadVoices = () => { window.speechSynthesis.getVoices(); };
    loadVoices();
    window.speechSynthesis.onvoiceschanged = loadVoices;

    return () => {
      stopAudio();
    };
  }, []);

  useEffect(() => {
    if (step === 'finish' && !clinicalReport && !isEditorMode) {
      generateClinicalReport();
    }
  }, [step]);

  useEffect(() => {
    window.scrollTo({ top: step === 'verification' ? document.body.scrollHeight : 0, behavior: 'smooth' });
  }, [transcript, step]);

  // --- SERVICIOS AUXILIARES ---

  const generateClinicalReport = async () => {
    setIsGeneratingReport(true);
    const context = transcript.map(t => `${t.sender}: ${t.text}`).join('\n');
    const summary = await gemini.summarizeSession(currentPatientData, answers, context);
    setClinicalReport(summary);
    setIsGeneratingReport(false);
  };

  const sendResultsToCoordinator = () => {
    if (!currentPatientData.coordinatorEmail && !isEditorMode) {
      alert("No se ha encontrado el email del coordinador.");
      return;
    }
    const email = currentPatientData.coordinatorEmail || 'cuestionarioespejo@gmail.com';
    const subject = `RESULTADOS: ${currentPatientData.nombre || 'Paciente'} - Cuestionario Espejo`;
    const body = `INFORME DE SESIÓN - CUESTIONARIO ESPEJO\nPACIENTE: ${currentPatientData.nombre || 'N/A'}\nEDAD: ${currentPatientData.edad || 'N/A'}\n\nVALORACIÓN IA:\n${clinicalReport}\n\nRESPUESTAS:\n${Object.entries(answers).map(([qid, ans]) => `P${qid}: ${ans}`).join('\n')}`;
    window.location.href = `mailto:${email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  };

  // --- MOTOR DE AUDIO ---

  const playOrSpeak = async (text: string, audioData?: DualAudio): Promise<void> => {
    stopAudio();

    if (voice === Voice.NONE) {
        return new Promise(resolve => setTimeout(resolve, 1500));
    }

    setIsSpeaking(true);

    return new Promise((resolve) => {
      // 1. Audio Personalizado según género
      const customUrl = voice === Voice.MALE ? audioData?.male : audioData?.female;

      if (customUrl) {
        const audio = new Audio(customUrl);
        currentAudioRef.current = audio;
        audio.onended = () => {
          setIsSpeaking(false);
          currentAudioRef.current = null;
          resolve();
        };
        audio.onerror = () => {
          console.warn("Error reproduciendo audio custom, usando voz nativa");
          speakNative(text, resolve);
        };
        audio.play().catch(() => speakNative(text, resolve));
        return;
      }

      // 2. Voz Nativa
      speakNative(text, resolve);
    });
  };

  const speakNative = (text: string, onEnd: () => void) => {
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'es-ES';

    const voices = window.speechSynthesis.getVoices();
    const esVoices = voices.filter(v => v.lang.includes('es') || v.lang.includes('ES'));

    if (esVoices.length > 0) {
        if (voice === Voice.MALE) {
            const preferred = esVoices.find(v => 
              v.name.includes('Google español') || 
              v.name.includes('Microsoft Elena') || 
              v.name.includes('Paulina') ||
              v.name.includes('Mexico')
            );
            const maleGeneric = esVoices.find(v => v.name.toLowerCase().includes('male') || v.name.toLowerCase().includes('hombre'));

            utterance.voice = preferred || maleGeneric || esVoices[0];
            if (!preferred) utterance.pitch = 0.9; 
        } else {
             const femaleVoice = esVoices.find(v => v.name.toLowerCase().includes('female') || v.name.toLowerCase().includes('mujer')) || esVoices[0];
             utterance.voice = femaleVoice;
             utterance.pitch = 1.1; 
        }
    }

    utterance.onend = () => { setIsSpeaking(false); onEnd(); };
    utterance.onerror = () => { setIsSpeaking(false); onEnd(); };
    window.speechSynthesis.speak(utterance);
  };

  const stopAudio = () => {
    window.speechSynthesis.cancel();
    if (currentAudioRef.current) {
      currentAudioRef.current.pause();
      currentAudioRef.current = null;
    }
    setIsSpeaking(false);
  };

  // --- NAVEGACION ---

  const handleExit = () => {
    if (confirm("¿Estás seguro de que deseas abandonar el cuestionario? Tu progreso se perderá.")) {
      stopAudio();
      window.location.reload();
    }
  };

  const handleBack = () => {
    stopAudio();
    if (currentQuestionIndex > 0) {
      const prevIdx = currentQuestionIndex - 1;
      setCurrentQuestionIndex(prevIdx);
      setTranscript(t => t.slice(0, -1)); // Eliminar visualmente la última respuesta
      loadQuestion(prevIdx);
    }
  };

  // --- LOGICA DE SECUENCIA DE PREGUNTAS (CON BLOQUEO) ---

  const playQuestionSequence = async (q: Question, index: number) => {
    setIsInteractionLocked(true); // BLOQUEAR AL INICIO
    setVisibleOptions([]);

    // 1. Escenario
    const scenarioText = q.speechScript || q.scenario;
    await playOrSpeak(scenarioText, q.audio);

    // 2. Opciones una a una
    for (const opt of q.options) {
      setVisibleOptions(prev => [...prev, opt.key]); 
      const textToRead = `Opción ${opt.key}... ${opt.text}`;
      await playOrSpeak(textToRead, opt.audio);
    }

    // 3. Cierre (Solo primera pregunta)
    if (index === 0) {
      await playOrSpeak("¿Con cuál de estas situaciones te sientes más identificado?");
    }

    setIsInteractionLocked(false); // DESBLOQUEAR AL FINAL
  };

  // --- FLUJO DE SESION ---

  const startSession = async () => {
    setStep('verification');
    addMessage(globalConfig.welcomeText, 'ia');
    await playOrSpeak(globalConfig.welcomeText, globalConfig.welcomeAudio);

    addMessage(globalConfig.nameQuestionText, 'ia');
    await playOrSpeak(globalConfig.nameQuestionText, globalConfig.nameQuestionAudio);
  };

  const handleVerification = async (nameInput: string) => {
    stopAudio();
    const inputClean = nameInput.trim();
    addMessage(nameInput, 'user');

    if (verificationAttempts === 0) {
        const nameToMatch = isEditorMode ? "Coordinador" : (currentPatientData.nombre || "");
        const inputLower = inputClean.toLowerCase();
        const expectedLower = nameToMatch.split(' ')[0].toLowerCase();

        if (inputLower.includes(expectedLower) || expectedLower.includes(inputLower) || isEditorMode) {
            proceedToQuestionnaire();
        } else {
            const mismatchMsg = `El nombre no coincide con nuestros registros (${currentPatientData.nombre}). Por favor, escribe el nombre completo.`;
            setVerificationAttempts(1);
            addMessage(mismatchMsg, 'ia');
            await playOrSpeak(mismatchMsg);
        }
    } else {
        setCurrentPatientData({ ...currentPatientData, nombre: inputClean });
        const acceptedMsg = `Entendido, actualizamos tu ficha como "${inputClean}".`;
        addMessage(acceptedMsg, 'ia');
        await playOrSpeak(acceptedMsg);
        setTimeout(proceedToQuestionnaire, 500);
    }
  };

  const proceedToQuestionnaire = async () => {
    stopAudio();
    addMessage(globalConfig.startText, 'ia');
    await playOrSpeak(globalConfig.startText, globalConfig.startAudio);

    setStep('questionnaire');
    loadQuestion(0);
  };

  const loadQuestion = async (index: number) => {
    const q = questions[index];
    setVisibleOptions([]); 

    if (!q) {
      setStep('finish');
      const goodbye = `Ha sido un placer, ${currentPatientData.nombre?.split(' ')[0] || 'amigo/a'}.`;
      addMessage(goodbye, 'ia');
      await playOrSpeak(goodbye);
      return;
    }

    playQuestionSequence(q, index);
  };

  const handleAnswer = (key: string) => {
    if (isInteractionLocked) return; // DOBLE SEGURIDAD
    stopAudio();
    const q = questions[currentQuestionIndex];
    setAnswers(prev => ({ ...prev, [q.id]: key }));
    addMessage(`Me identifico con la opción ${key.toUpperCase()}`, 'user');

    const nextIdx = currentQuestionIndex + 1;
    setCurrentQuestionIndex(nextIdx);
    loadQuestion(nextIdx);
  };

  const addMessage = (text: string, sender: 'ia' | 'user') => {
    setTranscript(prev => [...prev, { text, sender }]);
  };

  // --- EDITOR LOGIC ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: string, subIndex?: number, gender: 'male' | 'female' = 'female') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => { 
        const result = event.target?.result as string;

        if (isEditingGlobal) {
           const newConfig = { ...globalConfig };
           if (field === 'welcome') newConfig.welcomeAudio = { ...newConfig.welcomeAudio, [gender]: result };
           if (field === 'name') newConfig.nameQuestionAudio = { ...newConfig.nameQuestionAudio, [gender]: result };
           if (field === 'start') newConfig.startAudio = { ...newConfig.startAudio, [gender]: result };
           setGlobalConfig(newConfig);
        } else if (editingQuestion) {
           if (field === 'scenario') {
              const audio = editingQuestion.audio || {};
              setEditingQuestion({ ...editingQuestion, audio: { ...audio, [gender]: result } }); 
           } else if (field === 'option' && typeof subIndex === 'number') {
              const newOptions = [...editingQuestion.options];
              const optAudio = newOptions[subIndex].audio || {};
              newOptions[subIndex].audio = { ...optAudio, [gender]: result };
              setEditingQuestion({ ...editingQuestion, options: newOptions });
           }
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const saveGlobalChanges = () => {
    localStorage.setItem('radar_global_config', JSON.stringify(globalConfig));
    setIsEditingGlobal(false);
  };

  const saveQuestionChanges = () => {
    if (!editingQuestion) return;
    const updated = questions.map(q => q.id === editingQuestion.id ? editingQuestion : q);
    setQuestions(updated);
    localStorage.setItem('radar_custom_questions', JSON.stringify(updated));
    setEditingQuestion(null);
  };

  const themeClasses = isDarkMode ? "bg-[#0a0f1a] text-white" : "bg-slate-50 text-indigo-950";
  const headerClasses = isDarkMode ? "bg-[#111827]/90 border-white/10" : "bg-white/90 border-blue-100 shadow-sm";
  const cardClasses = isDarkMode ? "bg-gradient-to-br from-blue-900 to-indigo-950 border-white/20 text-white" : "bg-white border-blue-100 text-indigo-950 shadow-xl shadow-blue-900/5";

  // --- RENDER HELPERS ---
  const AudioUploadButton = ({ label, hasAudio, onChange }: { label: string, hasAudio: boolean, onChange: (e: any) => void }) => (
    <label className={`cursor-pointer px-3 py-2 rounded-lg text-[10px] font-bold uppercase transition-all flex items-center gap-2 border ${hasAudio ? 'bg-green-500/10 text-green-400 border-green-500/30' : 'bg-white/5 text-slate-400 border-white/10 hover:bg-white/10'}`}>
       <i className={`fas ${hasAudio ? 'fa-check' : 'fa-microphone'}`}></i> {label}
       <input type="file" accept="audio/*" className="hidden" onChange={onChange} />
    </label>
  );

  return (
    <div className={`min-h-screen flex flex-col transition-all duration-500 selection:bg-blue-500/30 ${themeClasses}`}>
      <header className={`backdrop-blur-xl border-b p-3 sticky top-0 z-40 transition-colors ${headerClasses}`}>
        <div className="max-w-xl mx-auto flex justify-between items-center gap-3 relative">
          <Logo size="sm" isDark={isDarkMode} />

          <div className="flex items-center gap-2 pr-12"> 
             <div className={`flex rounded-2xl p-1 border ml-4 ${isDarkMode ? 'bg-white/5 border-white/10' : 'bg-blue-600/5 border-blue-200'}`}>
                <button onClick={() => setVoice(Voice.FEMALE)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase transition-all ${voice === Voice.FEMALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Mujer</button>
                <button onClick={() => setVoice(Voice.MALE)} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase transition-all ${voice === Voice.MALE ? 'bg-blue-600 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Hombre</button>
                <button onClick={() => { setVoice(Voice.NONE); stopAudio(); }} className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase transition-all ${voice === Voice.NONE ? 'bg-blue-900 text-white shadow-lg' : isDarkMode ? 'text-white' : 'text-blue-800'}`}>Silencio</button>
             </div>
          </div>

          {/* Botón Salir "X" Elegante en esquina derecha */}
          {step === 'questionnaire' && (
            <button 
              onClick={handleExit} 
              className={`absolute right-0 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-full transition-all group ${isDarkMode ? 'hover:bg-red-900/30 text-slate-400 hover:text-red-400' : 'hover:bg-red-50 text-slate-400 hover:text-red-500'}`}
              title="Abandonar cuestionario"
            >
              <i className="fas fa-times text-lg"></i>
            </button>
          )}
        </div>
      </header>

      <div className="flex-1 max-w-2xl mx-auto w-full px-4 pt-6 pb-24 overflow-hidden">
        {step === 'questionnaire' && <div className="mb-6"><ProgressBar current={currentQuestionIndex + 1} total={questions.length} /></div>}

        <div className="mb-6 space-y-6">
          {step === 'verification' && (
             <div className="space-y-4 pb-4">
                {transcript.map((msg, i) => <ChatBubble key={i} msg={msg} isDarkMode={isDarkMode} />)}
             </div>
          )}

          {step === 'questionnaire' && questions[currentQuestionIndex] ? (
            <div className={`p-8 pt-12 rounded-[3rem] relative border animate-in fade-in duration-700 ${cardClasses}`}>

              {/* Cabecera con Texto y Botón de Retroceso alineados */}
              <div className="flex justify-between items-center mb-4">
                <span className={`text-[10px] font-black uppercase tracking-[0.4em] block ${isDarkMode ? 'text-blue-300' : 'text-blue-600'}`}>Reflexión del Momento</span>

                {currentQuestionIndex > 0 && (
                  <button 
                    onClick={handleBack} 
                    disabled={isInteractionLocked}
                    className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${isDarkMode ? 'bg-white/10 text-white hover:bg-white/20' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'} disabled:opacity-30`}
                    title="Pregunta anterior"
                  >
                    <i className="fas fa-arrow-left text-sm"></i>
                  </button>
                )}
              </div>

              <h2 className="text-xl md:text-2xl font-friendly font-bold leading-relaxed">{questions[currentQuestionIndex].scenario}</h2>
              {isEditorMode && (
                <button onClick={() => setEditingQuestion(questions[currentQuestionIndex])} className="absolute -bottom-4 -right-4 bg-blue-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-4 border-slate-50"><i className="fas fa-edit text-sm"></i></button>
              )}
            </div>
          ) : step === 'finish' ? (
            <div className={`text-center py-12 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-white/5 border-white/20' : 'bg-white border-blue-100'}`}>
               <div className="mb-8"><div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-3xl mx-auto mb-4 animate-in zoom-in duration-500"><i className="fas fa-check"></i></div><h2 className={`text-2xl font-bold mb-2 font-friendly ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>¡Gracias {currentPatientData.nombre?.split(' ')[0]}!</h2></div>
               {isGeneratingReport ? <div className="flex flex-col items-center gap-4 py-6"><div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div><p className="text-xs font-black uppercase text-blue-500 animate-pulse">Generando Informe...</p></div> : <div className="px-6 pb-8 animate-in slide-in-from-bottom-4"><p className="text-xs text-slate-400 mb-6">Tus respuestas y la valoración del Radar están listas para ser enviadas a tu coordinador.</p><Button onClick={sendResultsToCoordinator} className="w-full py-4 text-lg shadow-xl shadow-green-500/20 bg-green-600 hover:bg-green-700"><i className="fas fa-paper-plane mr-2"></i> Enviar Resultados al Profesional</Button></div>}
               {isEditorMode && <Button onClick={onExitEditor} variant="outline" className="mt-4 mx-6">Salir del Editor</Button>}
            </div>
          ) : step === 'intro' ? (
            <div className="min-h-[60vh] flex flex-col items-center justify-center gap-8 animate-in zoom-in-95 duration-700">
              <Button onClick={startSession} className="scale-125 px-12 py-8 shadow-2xl animate-pulse rounded-[2.5rem] text-xl tracking-wide">Empezar Cuestionario</Button>
              {isEditorMode && <button onClick={() => setIsEditingGlobal(true)} className="flex items-center gap-2 px-4 py-2 rounded-full bg-slate-200 text-slate-600 text-xs font-bold hover:bg-slate-300 transition-colors"><i className="fas fa-cog"></i> Configurar Mensajes y Voces</button>}
            </div>
          ) : null}
        </div>

        {step === 'questionnaire' && questions[currentQuestionIndex] && (
          <div className="space-y-4">
            {questions[currentQuestionIndex].options.map((opt, idx) => (
              visibleOptions.includes(opt.key) && (
                <button 
                  key={opt.key} 
                  disabled={isInteractionLocked}
                  onClick={() => handleAnswer(opt.key)} 
                  className={`w-full text-left p-5 rounded-2xl border-2 transition-all shadow-lg active:scale-[0.98] animate-option flex items-start gap-4 ${
                     isInteractionLocked ? 'opacity-50 cursor-wait' : 'cursor-pointer hover:border-blue-600'
                  } ${isDarkMode ? 'bg-white/10 border-white/20 hover:bg-blue-500/20' : 'bg-white border-blue-100 hover:bg-blue-50'}`}
                >
                  <span className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-black text-xs ${isDarkMode ? 'bg-blue-500 text-white' : 'bg-blue-600 text-white'}`}>{opt.key.toUpperCase()}</span>
                  <span className={`font-bold leading-relaxed text-lg ${isDarkMode ? 'text-white' : 'text-indigo-950'}`}>{opt.text}</span>
                </button>
              )
            ))}
          </div>
        )}
      </div>

      {(step === 'verification' || step === 'questionnaire') && (
        <footer className={`fixed bottom-0 left-0 right-0 p-3 border-t z-30 backdrop-blur-3xl shadow-2xl ${isDarkMode ? 'bg-[#0a0f1a]/95 border-white/10' : 'bg-white/95 border-blue-100'}`}>
          <div className="max-w-xl mx-auto flex flex-col items-center">
            {step === 'verification' && (
              <div className="flex gap-3 w-full max-w-md animate-in slide-in-from-bottom-6 mb-3">
                <input type="text" placeholder="Escribe aquí..." className={`flex-1 px-4 py-4 rounded-2xl border-2 outline-none font-black transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/20 focus:border-blue-500' : 'bg-blue-50 text-indigo-950 border-blue-200 focus:border-blue-600'}`} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyPress={e => e.key === 'Enter' && inputValue && (handleVerification(inputValue), setInputValue(''))} />
                <Button onClick={() => { if(inputValue) { handleVerification(inputValue); setInputValue(''); } }} className="px-6">Confirmar</Button>
              </div>
            )}
            <div className="flex items-center gap-6 pb-2">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all border ${isDarkMode ? 'bg-white/5 border-white/20 text-blue-400' : 'bg-blue-600/10 border-blue-600 text-blue-700'}`}><i className={`fas ${isDarkMode ? 'fa-sun' : 'fa-moon'}`}></i></button>
              <button disabled={voice === Voice.NONE} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-blue-600 hover:bg-blue-700' } text-white disabled:opacity-30`} onMouseDown={() => setIsRecording(true)} onMouseUp={() => setIsRecording(false)}><i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i></button>
              <div className="flex gap-1 items-end h-6 min-w-[30px]">{isSpeaking && [1,2,3].map(i => <div key={i} className="w-1 bg-blue-500 rounded-full animate-wave" style={{height: '60%', animationDelay: `${i*0.1}s`}}></div>)}</div>
            </div>
          </div>
        </footer>
      )}

      {/* EDITOR GLOBAL (INTRO, NOMBRE, INICIO) */}
      {isEditingGlobal && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
           <Card className="w-full max-w-4xl p-8 bg-[#111827] border-white/20 text-white overflow-y-auto max-h-[90vh] rounded-[3rem]">
              <h3 className="text-2xl font-bold font-friendly mb-6 flex items-center gap-3"><i className="fas fa-cog text-blue-500"></i> Configuración Global y Textos</h3>

              <div className="space-y-8">
                 <div className="bg-white/5 p-6 rounded-3xl border border-white/10">
                    <label className="block text-[10px] font-black uppercase text-blue-400 mb-4">Voz por Defecto al Iniciar</label>
                    <div className="flex gap-4">
                       {[Voice.FEMALE, Voice.MALE, Voice.NONE].map(v => (
                         <button key={v} onClick={() => setGlobalConfig({...globalConfig, defaultVoiceMode: v})} className={`px-4 py-2 rounded-xl text-xs font-bold uppercase ${globalConfig.defaultVoiceMode === v ? 'bg-blue-600 text-white' : 'bg-white/10 text-slate-400'}`}>{v === 'none' ? 'Silencio' : v === 'male' ? 'Hombre' : 'Mujer'}</button>
                       ))}
                    </div>
                 </div>

                 {[{id: 'welcome', label: '1. Mensaje de Bienvenida (Intro)'}, {id: 'name', label: '2. Pregunta por el Nombre'}, {id: 'start', label: '3. Mensaje Inicio Cuestionario'}].map((section) => (
                    <div key={section.id} className="space-y-4 border-t border-white/10 pt-4">
                       <label className="block text-sm font-bold text-indigo-300">{section.label}</label>
                       <textarea className="w-full bg-white/5 border-2 border-white/10 rounded-xl p-3 text-sm font-medium outline-none focus:border-blue-500" value={(globalConfig as any)[`${section.id}Text`]} onChange={e => setGlobalConfig({...globalConfig, [`${section.id}Text`]: e.target.value})} />
                       <div className="flex gap-4">
                          <AudioUploadButton label="Audio Mujer" hasAudio={!!(globalConfig as any)[`${section.id}Audio`]?.female} onChange={(e) => handleFileUpload(e, section.id, undefined, 'female')} />
                          <AudioUploadButton label="Audio Hombre" hasAudio={!!(globalConfig as any)[`${section.id}Audio`]?.male} onChange={(e) => handleFileUpload(e, section.id, undefined, 'male')} />
                       </div>
                    </div>
                 ))}
              </div>
              <div className="flex gap-4 mt-8 pt-6 border-t border-white/10">
                 <Button onClick={saveGlobalChanges} className="flex-1">Guardar Configuración</Button>
                 <Button variant="outline" onClick={() => setIsEditingGlobal(false)} className="flex-1 border-white/20 text-white">Cancelar</Button>
              </div>
           </Card>
        </div>
      )}

      {/* EDITOR DE PREGUNTAS (AUDIO DOBLE) */}
      {editingQuestion && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4">
          <Card className="w-full max-w-5xl p-6 md:p-10 shadow-2xl border-white/20 bg-[#111827] overflow-y-auto max-h-[95vh] rounded-[3rem]">
            <div className="flex justify-between items-center mb-8 border-b pb-4 border-white/10">
              <h3 className="text-2xl font-bold text-white font-friendly flex items-center gap-4"><i className="fas fa-edit text-blue-500"></i> Editar Pregunta</h3>
              <button onClick={() => setEditingQuestion(null)} className="text-white hover:text-red-400 transition-colors"><i className="fas fa-times text-xl"></i></button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black uppercase text-blue-400 mb-2">Escenario</label>
                  <textarea className="w-full border-2 border-white/10 bg-white/5 p-4 rounded-2xl text-sm font-black min-h-[120px] outline-none focus:border-blue-500 text-white leading-relaxed" value={editingQuestion.scenario} onChange={e => setEditingQuestion({...editingQuestion, scenario: e.target.value})} />
                  <div className="flex gap-4 mt-3">
                     <AudioUploadButton label="Audio Escenario (Mujer)" hasAudio={!!editingQuestion.audio?.female} onChange={(e) => handleFileUpload(e, 'scenario', undefined, 'female')} />
                     <AudioUploadButton label="Audio Escenario (Hombre)" hasAudio={!!editingQuestion.audio?.male} onChange={(e) => handleFileUpload(e, 'scenario', undefined, 'male')} />
                  </div>
                </div>

                <div className="space-y-4">
                    <label className="block text-[10px] font-black uppercase text-blue-400">Opciones</label>
                    {editingQuestion.options.map((opt, idx) => (
                        <div key={opt.key} className="bg-white/5 p-4 rounded-xl border border-white/5">
                            <div className="flex gap-3 mb-3">
                                <span className="w-8 h-8 rounded-lg bg-blue-500/20 text-blue-400 flex items-center justify-center font-black text-xs shrink-0">{opt.key.toUpperCase()}</span>
                                <input className="flex-1 border-2 border-white/10 bg-transparent px-3 py-1 rounded-lg text-sm text-white" value={opt.text} onChange={e => { const opts = [...editingQuestion.options]; opts[idx].text = e.target.value; setEditingQuestion({...editingQuestion, options: opts}); }} />
                            </div>
                            <div className="flex gap-3 pl-11">
                                <AudioUploadButton label="Audio Opción (M)" hasAudio={!!opt.audio?.female} onChange={(e) => handleFileUpload(e, 'option', idx, 'female')} />
                                <AudioUploadButton label="Audio Opción (H)" hasAudio={!!opt.audio?.male} onChange={(e) => handleFileUpload(e, 'option', idx, 'male')} />
                            </div>
                        </div>
                    ))}
                </div>
              </div>
              <div className="bg-blue-900/10 p-6 rounded-[2.5rem] border border-blue-500/20 h-fit">
                <p className="text-xs text-blue-200 leading-relaxed font-medium"><i className="fas fa-info-circle mr-2"></i><strong>Sistema Dual:</strong> Ahora puedes subir un audio específico para la voz de MUJER y otro para la de HOMBRE. El sistema reproducirá automáticamente el que corresponda según la selección del usuario en la barra superior.</p>
              </div>
            </div>
            <div className="flex gap-4 pt-8 border-t border-white/10 mt-8"><Button className="flex-1 py-4 text-lg" onClick={saveQuestionChanges}>Guardar Cambios</Button><Button variant="outline" className="flex-1 py-4 border-white/20 text-white font-black" onClick={() => setEditingQuestion(null)}>Cancelar</Button></div>
          </Card>
        </div>
      )}
    </div>
  );
};
